default-ad-setup.js.content:
// Script to insert a default advertisement into the database
// Run this with: node --experimental-modules default-ad-setup.js
// or: node default-ad-setup.js (if using Node.js v14.8.0 or later)

const fetch = (...args) => import('node-fetch').then(({default: fetch}) => fetch(...args));

// The HTML for our default advertisement
const defaultAdHTML = `
<script>
var atOptions = { 
  'key' : 'a1234567890abcdef1234567890abcdef', 
  'format' : 'iframe', 
  'height' : 300, 
  'width' : 160, 
  'params' : {} 
};
document.write('<scr' + 'ipt type="text/javascript" src="http://www.example-ad-network.com/a/display.js"></scr' + 'ipt>');
</script>
`;

async function createDefaultAd() {
  try {
    // First, login as admin
    const loginResponse = await fetch('http://localhost:5000/api/login', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        username: 'shadowHimel',
        password: 'himel1122'
      }),
      credentials: 'include'
    });

    if (!loginResponse.ok) {
      throw new Error(`Login failed: ${loginResponse.statusText}`);
    }

    const userData = await loginResponse.json();
    console.log(`Logged in as ${userData.username}`);

    // Now create the advertisement
    const adResponse = await fetch('http://localhost:5000/api/admin/advertisement', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        html: defaultAdHTML,
        frequency: 100,
        isEnabled: true,
        isDefault: true
      }),
      credentials: 'include'
    });

    if (!adResponse.ok) {
      throw new Error(`Failed to create advertisement: ${adResponse.statusText}`);
    }

    const adData = await adResponse.json();
    console.log(`Default advertisement created with ID: ${adData.id}`);
    console.log('Success! The default permanent advertisement has been created.');

  } catch (error) {
    console.error('Error creating default advertisement:', error);
  }
}

createDefaultAd();

delete-admin.js.content:
import fetch from 'node-fetch';

async function deleteAdminUser() {
  try {
    // First login as an admin to get authentication token
    const loginResponse = await fetch('http://localhost:5000/api/login', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        username: 'Albab AJ',
        password: 'admin1122'
      })
    });

    if (!loginResponse.ok) {
      throw new Error('Admin login failed');
    }

    const { token } = await loginResponse.json();

    // Get all users to find shadowHimel2's ID
    const usersResponse = await fetch('http://localhost:5000/api/admin/users', {
      headers: {
        'Authorization': `Bearer ${token}`
      }
    });

    const users = await usersResponse.json();
    const userToDelete = users.find(u => u.username === 'shadowHimel2');

    if (!userToDelete) {
      console.log('User shadowHimel2 not found');
      return;
    }

    // Delete the user
    const deleteResponse = await fetch(`http://localhost:5000/api/admin/users/${userToDelete.id}`, {
      method: 'DELETE',
      headers: {
        'Authorization': `Bearer ${token}`
      }
    });

    if (deleteResponse.ok) {
      console.log('Successfully deleted user shadowHimel2');
    } else {
      console.log('Failed to delete user:', await deleteResponse.text());
    }
  } catch (error) {
    console.error('Error:', error);
  }
}

deleteAdminUser();

