import { Client } from "@notionhq/client";

// Initialize Notion client
export const notion = new Client({
  auth: process.env.NOTION_INTEGRATION_SECRET,
});

// Extract the page ID from the Notion page URL
export function extractPageIdFromUrl(pageUrl: string): string {
  // Handle URLs in different formats
  // Format 1: https://www.notion.so/{workspace}/{page-id}
  // Format 2: https://www.notion.so/{page-id}
  // Format 3: https://www.notion.so/{page-id}?{query-params}
  try {
    const match = pageUrl.match(/([a-f0-9]{32})(?:[?#]|$)/i);
    if (match && match[1]) {
      return match[1];
    }

    throw new Error("Invalid Notion page URL format");
  } catch (error) {
    console.error("Error extracting page ID:", error);
    throw new Error("Failed to extract page ID from URL");
  }
}

// Get the page ID from environment variable or use a default for development
let pageIdToUse: string;
try {
  if (process.env.NOTION_PAGE_URL) {
    pageIdToUse = extractPageIdFromUrl(process.env.NOTION_PAGE_URL);
    console.log(`Using Notion page ID: ${pageIdToUse}`);
  } else if (process.env.NODE_ENV === 'development') {
    pageIdToUse = "placeholder_page_id_for_development";
    console.log("Using placeholder page ID for development environment");
  } else {
    pageIdToUse = "default_page_id";
    console.warn("No Notion page URL provided, using default page ID");
  }
} catch (error) {
  pageIdToUse = "fallback_page_id";
  console.warn("Failed to parse Notion page ID, using fallback ID");
}

export const NOTION_PAGE_ID = pageIdToUse;

/**
 * Lists all child databases contained within NOTION_PAGE_ID
 * @returns {Promise<Array<any>>} - Array of database objects with id and title
 */
export async function getNotionDatabases() {
  // Array to store the child databases
  const childDatabases = [];

  try {
    // Query all child blocks in the specified page
    let hasMore = true;
    let startCursor: string | undefined = undefined;

    while (hasMore) {
      const response = await notion.blocks.children.list({
        block_id: NOTION_PAGE_ID,
        start_cursor: startCursor,
      });

      // Process the results
      for (const block of response.results) {
        // Check if the block is a child database
        if ('type' in block && block.type === "child_database") {
          const databaseId = block.id;

          // Retrieve the database title
          try {
            const databaseInfo = await notion.databases.retrieve({
              database_id: databaseId,
            });

            // Add the database to our list
            childDatabases.push(databaseInfo);
          } catch (error) {
            console.error(`Error retrieving database ${databaseId}:`, error);
          }
        }
      }

      // Check if there are more results to fetch
      hasMore = response.has_more;
      startCursor = response.next_cursor || undefined;
    }

    return childDatabases;
  } catch (error) {
    console.error("Error listing child databases:", error);
    throw error;
  }
}

// Find get a Notion database with the matching title
export async function findDatabaseByTitle(title: string) {
  const databases = await getNotionDatabases();

  for (const db of databases) {
    // Handle different formats of the title property in Notion API responses
    const dbTitle = getNotionDatabaseTitle(db);
    if (dbTitle.toLowerCase() === title.toLowerCase()) {
      return db;
    }
  }

  return null;
}

// Extract the title from a Notion database object (handles different API response formats)
function getNotionDatabaseTitle(database: any): string {
  if (!database) return "";

  // Handle different formats of title in the Notion API
  if (database.title && Array.isArray(database.title)) {
    // Format 1: title is an array of rich text objects
    return database.title[0]?.plain_text || "";
  } else if (database.title && typeof database.title === 'object') {
    // Format 2: title is a property object
    return database.title.title?.[0]?.plain_text || "";
  } else if (database.properties && database.properties.title) {
    // Format 3: title is in properties
    return database.properties.title.title?.[0]?.plain_text || "";
  } else if (database.properties && database.properties.Title) {
    // Format 4: Title (capital T) is in properties
    return database.properties.Title.title?.[0]?.plain_text || "";
  } else if (database.properties && database.properties.Name) {
    // Format 5: Name is in properties
    return database.properties.Name.title?.[0]?.plain_text || "";
  } else if (database.properties && database.properties.name) {
    // Format 6: name (lowercase) is in properties
    return database.properties.name.title?.[0]?.plain_text || "";
  }

  // If no title can be found
  return "";
}

// Create a new database if one with a matching title does not exist
export async function createDatabaseIfNotExists(title: string, properties: any) {
  try {
    const existingDb = await findDatabaseByTitle(title);
    if (existingDb) {
      console.log(`Database "${title}" already exists with ID: ${existingDb.id}`);
      return existingDb;
    }

    console.log(`Creating new database "${title}"...`);
    return await notion.databases.create({
      parent: {
        type: "page_id",
        page_id: NOTION_PAGE_ID
      },
      title: [
        {
          type: "text",
          text: {
            content: title
          }
        }
      ],
      properties
    });
  } catch (error) {
    console.error(`Error creating database "${title}":`, error);
    throw error;
  }
}

// Create a new page in a Notion database
export async function createNotionPage(databaseId: string, properties: any) {
  try {
    return await notion.pages.create({
      parent: {
        database_id: databaseId
      },
      properties
    });
  } catch (error) {
    console.error("Error creating Notion page:", error);
    throw error;
  }
}

// Helper function to get promotions (used in client app)
export async function getPromotions() {
  try {
    const promotionsDb = await findDatabaseByTitle("Promotions");
    if (!promotionsDb) {
      throw new Error("Promotions database not found");
    }

    const response = await notion.databases.query({
      database_id: promotionsDb.id,
      filter: {
        property: "Active",
        checkbox: {
          equals: true
        }
      }
    });

    return response.results.map((page: any) => {
      const properties = page.properties;

      return {
        id: page.id,
        title: properties.Title?.title?.[0]?.plain_text || "Untitled Promotion",
        description: properties.Description?.rich_text?.[0]?.plain_text || "",
        startDate: properties.StartDate?.date?.start || null,
        endDate: properties.EndDate?.date?.start || null,
        rewardType: properties.RewardType?.select?.name || "Bonus",
        amount: properties.Amount?.number || 0
      };
    });
  } catch (error) {
    console.error("Error fetching promotions:", error);
    throw error;
  }
}

// Helper function to get game configurations
export async function getGameConfigurations() {
  try {
    const gameConfigDb = await findDatabaseByTitle("Game Configurations");
    if (!gameConfigDb) {
      throw new Error("Game Configurations database not found");
    }

    const response = await notion.databases.query({
      database_id: gameConfigDb.id,
      filter: {
        property: "Enabled",
        checkbox: {
          equals: true
        }
      }
    });

    // Group configurations by game type
    const configsByGame: Record<string, any> = {};

    response.results.forEach((page: any) => {
      const properties = page.properties;
      const gameType = properties.GameType?.select?.name || "Global";
      const parameter = properties.Parameter?.select?.name || "";
      const value = properties.Value?.number ?? 0;

      if (!configsByGame[gameType]) {
        configsByGame[gameType] = {};
      }

      // Convert parameter to camelCase
      const paramKey = parameter
        .replace(/\s(.)/g, (_: string, $1: string) => $1.toLowerCase())
        .replace(/\s/g, '')
        .replace(/^(.)/, (_: string, $1: string) => $1.toLowerCase());

      configsByGame[gameType][paramKey] = value;
    });

    return configsByGame;
  } catch (error) {
    console.error("Error fetching game configurations:", error);
    throw error;
  }
}

// Helper function to get loyalty tiers
export async function getLoyaltyTiers() {
  try {
    const loyaltyDb = await findDatabaseByTitle("Loyalty Tiers");
    if (!loyaltyDb) {
      // Return default tiers if database doesn't exist yet
      return [
        { name: "Bronze", points: 0, cashbackRate: 0.01 },
        { name: "Silver", points: 100, cashbackRate: 0.02 },
        { name: "Gold", points: 500, cashbackRate: 0.03 },
        { name: "Platinum", points: 1000, cashbackRate: 0.05 },
        { name: "Diamond", points: 5000, cashbackRate: 0.07 }
      ];
    }

    const response = await notion.databases.query({
      database_id: loyaltyDb.id,
      sorts: [
        {
          property: "Points",
          direction: "ascending"
        }
      ]
    });

    return response.results.map((page: any) => {
      const properties = page.properties;

      return {
        name: properties.Name?.title?.[0]?.plain_text || "Unknown Tier",
        points: properties.Points?.number || 0,
        cashbackRate: properties.CashbackRate?.number || 0,
        color: properties.Color?.select?.name || "gray"
      };
    });
  } catch (error) {
    console.error("Error fetching loyalty tiers:", error);
    // Return default tiers on error
    return [
      { name: "Bronze", points: 0, cashbackRate: 0.01 },
      { name: "Silver", points: 100, cashbackRate: 0.02 },
      { name: "Gold", points: 500, cashbackRate: 0.03 },
      { name: "Platinum", points: 1000, cashbackRate: 0.05 },
      { name: "Diamond", points: 5000, cashbackRate: 0.07 }
    ];
  }
}

// Helper function to get FAQs
export async function getFAQs() {
  try {
    const faqsDb = await findDatabaseByTitle("FAQs");
    if (!faqsDb) {
      // Return empty array if database doesn't exist yet
      return [];
    }

    const response = await notion.databases.query({
      database_id: faqsDb.id,
      sorts: [
        {
          property: "Priority",
          direction: "ascending"
        }
      ]
    });

    return response.results.map((page: any) => {
      const properties = page.properties;

      return {
        id: page.id,
        question: properties.Question?.rich_text?.[0]?.plain_text || "Unknown question",
        answer: properties.Answer?.rich_text?.[0]?.plain_text || "No answer provided",
        category: properties.Category?.select?.name || "General"
      };
    });
  } catch (error) {
    console.error("Error fetching FAQs:", error);
    return [];
  }
}

server/plinko-master-service.ts.content:
export interface PlinkoMasterOptions {
  forceWin?: boolean;
  forceLose?: boolean;
  numBalls?: number;
  risk?: 'low' | 'medium' | 'high';
  rows?: number;
}

export interface PlinkoMasterResult {
  slotIndex: number;
  multiplier: number;
  payout: number;
  profit: number;
  result: "WIN" | "LOSS" | "BREAK-EVEN";
  ballPath: number[];
  isWin: boolean;
  risk: 'low' | 'medium' | 'high';
  rows: number;
}

export class PlinkoMasterService {
  // Stake.com authentic multiplier patterns for 16 rows
  private static readonly MULTIPLIER_PATTERNS = {
    low: [16, 9, 2, 1.4, 1.2, 1.1, 1, 0.5, 0.5, 1, 1.1, 1.2, 1.4, 2, 9, 16],           // Low Risk: Max 16x
    medium: [110, 41, 10, 5, 3, 1.5, 1, 0.5, 0.5, 1, 1.5, 3, 5, 10, 41, 110],          // Medium Risk: Max 110x (user requested)
    high: [1000, 130, 26, 8, 3, 1.5, 1, 0.2, 0.2, 1, 1.5, 3, 8, 26, 130, 1000]         // High Risk: Max 1000x
  };

  private static readonly ROWS = 16;

  /**
   * Simulate a realistic ball drop through pins
   * @param startPosition Starting position (default: center)
   * @returns Array of directions (0 = left, 1 = right) for each row
   */
  static simulateBallPath(startPosition: number = 7.5): number[] {
    const ballPath: number[] = [];
    let currentPosition = startPosition;

    for (let row = 0; row < this.ROWS; row++) {
      // Each pin hit has 50/50 chance to go left (0) or right (1)
      const direction = Math.random() > 0.5 ? 1 : 0;
      ballPath.push(direction);

      // Update position based on direction
      currentPosition += direction === 1 ? 0.5 : -0.5;
    }

    return ballPath;
  }

  /**
   * Calculate final slot index based on ball path
   * @param ballPath Array of directions
   * @param startPosition Starting position
   * @returns Final slot index (0-15)
   */
  static calculateSlotIndex(ballPath: number[], startPosition: number = 7.5): number {
    let position = startPosition;

    for (const direction of ballPath) {
      position += direction === 1 ? 0.5 : -0.5;
    }

    // Round to nearest slot and clamp to valid range (always 16 slots)
    const slotIndex = Math.round(position);
    return Math.max(0, Math.min(slotIndex, 15)); // 16 slots = indices 0-15
  }

  /**
   * Get multiplier array for a specific risk level
   * @param risk Risk level
   * @returns Array of multipliers
   */
  static getMultipliers(risk: 'low' | 'medium' | 'high' = 'medium'): number[] {
    return [...this.MULTIPLIER_PATTERNS[risk]];
  }

  /**
   * Apply rigging to force specific outcomes
   * @param forceWin Force a winning outcome
   * @param forceLose Force a losing outcome
   * @param risk Risk level to determine multiplier pattern
   * @returns Forced slot index or null if no rigging
   */
  static applyRigging(forceWin?: boolean, forceLose?: boolean, risk: 'low' | 'medium' | 'high' = 'medium'): number | null {
    const multipliers = this.getMultipliers(risk);

    if (forceWin) {
      // Get all winning slots (multiplier >= 1.0)
      const winningSlots = multipliers
        .map((mult, idx) => ({ mult, idx }))
        .filter(slot => slot.mult >= 1.0)
        .map(slot => slot.idx);

      return winningSlots[Math.floor(Math.random() * winningSlots.length)];
    }

    if (forceLose) {
      // Get all losing slots (multiplier < 1.0)
      const losingSlots = multipliers
        .map((mult, idx) => ({ mult, idx }))
        .filter(slot => slot.mult < 1.0)
        .map(slot => slot.idx);

      return losingSlots[Math.floor(Math.random() * losingSlots.length)];
    }

    return null;
  }

  /**
   * Play a single Plinko Master game
   * @param betAmount Bet amount in currency
   * @param options Game options (rigging, risk level, etc.)
   * @returns Game result with all calculations
   */
  static playGame(betAmount: number, options: PlinkoMasterOptions = {}): PlinkoMasterResult {
    const risk = options.risk || 'medium';
    const rows = options.rows || 16;
    const multipliers = this.getMultipliers(risk);

    let slotIndex: number;
    let ballPath: number[];

    // Check for rigging first
    if (options.forceWin) {
      slotIndex = this.applyRigging(true, false, risk) || 0;
      ballPath = this.generatePathToSlot(slotIndex);
    } else if (options.forceLose) {
      slotIndex = this.applyRigging(false, true, risk) || 0;
      ballPath = this.generatePathToSlot(slotIndex);
    } else {
      // Simulate realistic ball drop through pins
      ballPath = this.simulateBallPath();
      slotIndex = this.calculateSlotIndex(ballPath);
    }

    // Get multiplier for the slot
    const multiplier = multipliers[slotIndex];

    // Calculate payout and profit with 2 decimal precision
    const payout = parseFloat((betAmount * multiplier).toFixed(2));
    const profit = parseFloat((payout - betAmount).toFixed(2));

    // Determine result type
    let result: "WIN" | "LOSS" | "BREAK-EVEN";
    if (payout > betAmount) {
      result = "WIN";
    } else if (payout < betAmount) {
      result = "LOSS";
    } else {
      result = "BREAK-EVEN";
    }

    return {
      slotIndex,
      multiplier,
      payout,
      profit,
      result,
      ballPath,
      isWin: result === "WIN",
      risk,
      rows
    };
  }

  /**
   * Generate a ball path that leads to a specific slot
   * @param targetSlot Target slot index (0-15)
   * @returns Ball path that leads to the target slot
   */
  static generatePathToSlot(targetSlot: number): number[] {
    const ballPath: number[] = [];
    const startPosition = 7.5;
    let currentPosition = startPosition;
    const targetPosition = targetSlot;

    for (let row = 0; row < this.ROWS; row++) {
      // Calculate how far we need to move to reach target
      const remainingRows = this.ROWS - row;
      const requiredMovement = targetPosition - currentPosition;

      // Decide direction based on required movement and some randomness
      let direction: number;

      if (remainingRows === 0) {
        direction = Math.random() > 0.5 ? 1 : 0;
      } else {
        const idealDirection = requiredMovement > 0 ? 1 : 0;
        const maxPossibleMovement = remainingRows * 0.5;

        // If we can still reach the target with some randomness
        if (Math.abs(requiredMovement) <= maxPossibleMovement) {
          // 70% chance to move in ideal direction, 30% random
          direction = Math.random() < 0.7 ? idealDirection : (Math.random() > 0.5 ? 1 : 0);
        } else {
          // Must move in ideal direction
          direction = idealDirection;
        }
      }

      ballPath.push(direction);
      currentPosition += direction === 1 ? 0.5 : -0.5;
    }

    return ballPath;
  }

  /**
   * Get multiplier for a specific slot
   * @param slotIndex Slot index (0-15)
   * @param risk Risk level
   * @returns Multiplier value
   */
  static getMultiplier(slotIndex: number, risk: 'low' | 'medium' | 'high' = 'medium'): number {
    const multipliers = this.getMultipliers(risk);
    if (slotIndex < 0 || slotIndex >= multipliers.length) {
      throw new Error(`Invalid slot index: ${slotIndex}`);
    }
    return multipliers[slotIndex];
  }

  /**
   * Get all multipliers for a specific risk level
   * @param risk Risk level
   * @returns Array of all multipliers
   */
  static getAllMultipliers(risk: 'low' | 'medium' | 'high' = 'medium'): number[] {
    return this.getMultipliers(risk);
  }
}

