import multer from 'multer';
import path from 'path';
import fs from 'fs';
import crypto from 'crypto';

// Ensure upload directories exist
const uploadDir = path.join(process.cwd(), 'public', 'uploads', 'profile-pictures');
const gameUploadDir = path.join(process.cwd(), 'uploaded_games');
const gameAssetsDir = path.join(process.cwd(), 'public', 'uploads', 'game-assets');

if (!fs.existsSync(uploadDir)) {
  fs.mkdirSync(uploadDir, { recursive: true });
}
if (!fs.existsSync(gameUploadDir)) {
  fs.mkdirSync(gameUploadDir, { recursive: true });
}
if (!fs.existsSync(gameAssetsDir)) {
  fs.mkdirSync(gameAssetsDir, { recursive: true });
}

// Configure multer storage
const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    cb(null, uploadDir);
  },
  filename: (req, file, cb) => {
    // Generate unique filename with timestamp and random string
    const uniqueSuffix = Date.now() + '-' + crypto.randomUUID();
    const extension = path.extname(file.originalname).toLowerCase();
    cb(null, `profile-${uniqueSuffix}${extension}`);
  }
});

// File filter for security
const fileFilter = (req: any, file: Express.Multer.File, cb: multer.FileFilterCallback) => {
  // Allow only specific image types
  const allowedTypes = ['image/jpeg', 'image/jpg', 'image/png', 'image/webp'];
  const allowedExtensions = ['.jpg', '.jpeg', '.png', '.webp'];

  const extension = path.extname(file.originalname).toLowerCase();

  if (allowedTypes.includes(file.mimetype) && allowedExtensions.includes(extension)) {
    cb(null, true);
  } else {
    cb(new Error('Invalid file type. Only JPEG, PNG, and WebP images are allowed.'));
  }
};

// Create multer instance with configuration
export const profilePictureUpload = multer({
  storage: storage,
  fileFilter: fileFilter,
  limits: {
    fileSize: 5 * 1024 * 1024, // 5MB limit
    files: 1 // Only one file at a time
  }
});

// Utility function to delete old profile picture
export function deleteOldProfilePicture(filename: string | null) {
  if (!filename) return;

  const filePath = path.join(uploadDir, filename);
  if (fs.existsSync(filePath)) {
    try {
      fs.unlinkSync(filePath);
    } catch (error) {
      console.error('Error deleting old profile picture:', error);
    }
  }
}

// Utility function to get profile picture URL
export function getProfilePictureUrl(filename: string | null): string | null {
  if (!filename) return null;
  return `/uploads/profile-pictures/${filename}`;
}

// Default avatar URL for users without profile pictures
export const DEFAULT_AVATAR_URL = '/assets/default-avatar.svg';

// Game file upload configuration
const gameFileStorage = multer.diskStorage({
  destination: (req, file, cb) => {
    cb(null, gameUploadDir);
  },
  filename: (req, file, cb) => {
    // Generate unique filename with timestamp and random string
    const uniqueSuffix = Date.now() + '-' + crypto.randomUUID();
    const extension = path.extname(file.originalname).toLowerCase();
    cb(null, `game-${uniqueSuffix}${extension}`);
  }
});

// Game file filter for security
const gameFileFilter = (req: any, file: Express.Multer.File, cb: multer.FileFilterCallback) => {
  // Allow game file types
  const allowedTypes = [
    'text/html', 'text/javascript', 'application/javascript',
    'text/typescript', 'application/typescript', 'text/tsx',
    'text/jsx', 'application/json', 'text/css', 'text/plain'
  ];
  const allowedExtensions = [
    '.html', '.htm', '.js', '.jsx', '.ts', '.tsx', 
    '.css', '.json', '.txt', '.md'
  ];

  const extension = path.extname(file.originalname).toLowerCase();

  if (allowedTypes.includes(file.mimetype) || allowedExtensions.includes(extension)) {
    cb(null, true);
  } else {
    cb(new Error('Invalid file type. Only HTML, JS, JSX, TS, TSX, CSS, JSON, and text files are allowed.'));
  }
};

// Create multer instance for game files
export const gameFileUpload = multer({
  storage: gameFileStorage,
  fileFilter: gameFileFilter,
  limits: {
    fileSize: 10 * 1024 * 1024, // 10MB limit for game files
    files: 5 // Allow multiple files for complex games
  }
});

// Game asset (image) upload configuration
const gameAssetStorage = multer.diskStorage({
  destination: (req, file, cb) => {
    cb(null, gameAssetsDir);
  },
  filename: (req, file, cb) => {
    const uniqueSuffix = Date.now() + '-' + crypto.randomUUID();
    const extension = path.extname(file.originalname).toLowerCase();
    cb(null, `asset-${uniqueSuffix}${extension}`);
  }
});

// Game asset filter (for thumbnails and game images)
const gameAssetFilter = (req: any, file: Express.Multer.File, cb: multer.FileFilterCallback) => {
  const allowedTypes = ['image/jpeg', 'image/jpg', 'image/png', 'image/webp', 'image/gif'];
  const allowedExtensions = ['.jpg', '.jpeg', '.png', '.webp', '.gif'];

  const extension = path.extname(file.originalname).toLowerCase();

  if (allowedTypes.includes(file.mimetype) && allowedExtensions.includes(extension)) {
    cb(null, true);
  } else {
    cb(new Error('Invalid file type. Only JPEG, PNG, WebP, and GIF images are allowed.'));
  }
};

// Create multer instance for game assets
export const gameAssetUpload = multer({
  storage: gameAssetStorage,
  fileFilter: gameAssetFilter,
  limits: {
    fileSize: 5 * 1024 * 1024, // 5MB limit for images
    files: 1
  }
});

// Utility functions for game files
export function deleteGameFile(filename: string | null) {
  if (!filename) return;

  const filePath = path.join(gameUploadDir, filename);
  if (fs.existsSync(filePath)) {
    try {
      fs.unlinkSync(filePath);
    } catch (error) {
      console.error('Error deleting game file:', error);
    }
  }
}

export function getGameFileUrl(filename: string | null): string | null {
  if (!filename) return null;
  return `/uploads/games/${filename}`;
}

export function getGameAssetUrl(filename: string | null): string | null {
  if (!filename) return null;
  return `/uploads/game-assets/${filename}`;
}

server/user-activity-tracker.ts.content:
import { storage } from './storage';

/**
 * Enhanced User Activity Tracker
 * Addresses the critical flaw where all users show as "Active" regardless of actual status
 * Implements proper session management and activity tracking
 */

interface ActivitySession {
  userId: string;
  username: string;
  lastActivity: Date;
  isActive: boolean;
  ipAddress?: string;
}

class UserActivityTracker {
  private activeSessions = new Map<string, ActivitySession>();
  private readonly ACTIVITY_TIMEOUT = 5 * 60 * 1000; // 5 minutes in milliseconds (more aggressive)
  private readonly CLEANUP_INTERVAL = 1 * 60 * 1000; // 1 minute in milliseconds (more frequent)
  private cleanupTimer: NodeJS.Timeout | null = null;

  constructor() {
    this.startCleanupProcess();
    // Force sync on startup to correct any inconsistent user statuses
    setTimeout(() => {
      this.forceSyncAllUsers();
    }, 2000); // Delay to allow storage to initialize
  }

  /**
   * Mark a user as active (called on login, API requests, etc.)
   */
  async markUserActive(userId: string, username: string, ipAddress?: string): Promise<void> {
    try {
      const session: ActivitySession = {
        userId,
        username,
        lastActivity: new Date(),
        isActive: true,
        ipAddress
      };

      this.activeSessions.set(userId, session);

      // Update storage to reflect online status
      await storage.updateUserOnlineStatus(userId, true);
      await storage.updateUserLastSeen(userId);

      console.log(`User ${username} marked as ACTIVE`);
    } catch (error) {
      console.error(`Failed to mark user ${username} as active:`, error);
    }
  }

  /**
   * Mark a user as inactive (called on logout, session timeout, etc.)
   */
  async markUserInactive(userId: string, reason: string = 'manual'): Promise<void> {
    try {
      const session = this.activeSessions.get(userId);
      if (session) {
        session.isActive = false;
        this.activeSessions.delete(userId);

        // Update storage to reflect offline status
        await storage.updateUserOnlineStatus(userId, false);

        console.log(`User ${session.username} marked as INACTIVE (reason: ${reason})`);
      }
    } catch (error) {
      console.error(`Failed to mark user ${userId} as inactive:`, error);
    }
  }

  /**
   * Update user activity timestamp (called on authenticated requests)
   */
  async updateUserActivity(userId: string): Promise<void> {
    try {
      const session = this.activeSessions.get(userId);
      if (session) {
        session.lastActivity = new Date();
        await storage.updateUserLastSeen(userId);
      }
    } catch (error) {
      console.error(`Failed to update activity for user ${userId}:`, error);
    }
  }

  /**
   * Get current activity status for a user
   */
  getUserActivityStatus(userId: string): { isActive: boolean; lastSeen?: Date } {
    const session = this.activeSessions.get(userId);
    if (!session) {
      return { isActive: false };
    }

    const timeSinceActivity = Date.now() - session.lastActivity.getTime();
    const isActive = timeSinceActivity < this.ACTIVITY_TIMEOUT;

    if (!isActive && session.isActive) {
      // User has timed out, mark as inactive
      this.markUserInactive(userId, 'timeout');
    }

    return {
      isActive,
      lastSeen: session.lastActivity
    };
  }

  /**
   * Get all currently active users
   */
  getActiveUsers(): ActivitySession[] {
    return Array.from(this.activeSessions.values()).filter(session => {
      const timeSinceActivity = Date.now() - session.lastActivity.getTime();
      return timeSinceActivity < this.ACTIVITY_TIMEOUT;
    });
  }

  /**
   * Get activity summary statistics
   */
  getActivitySummary(): { totalActive: number; totalSessions: number; activeUsers: string[] } {
    const activeUsers = this.getActiveUsers();
    return {
      totalActive: activeUsers.length,
      totalSessions: this.activeSessions.size,
      activeUsers: activeUsers.map(u => u.username)
    };
  }

  /**
   * Cleanup inactive sessions
   */
  private async cleanupInactiveSessions(): Promise<void> {
    try {
      const now = Date.now();
      let cleanedUp = 0;

      for (const [userId, session] of this.activeSessions.entries()) {
        const timeSinceActivity = now - session.lastActivity.getTime();

        if (timeSinceActivity > this.ACTIVITY_TIMEOUT) {
          await this.markUserInactive(userId, 'timeout');
          cleanedUp++;
        }
      }

      if (cleanedUp > 0) {
        console.log(`Activity cleanup: marked ${cleanedUp} users as inactive due to timeout`);
      }

      // Also sync with storage to ensure database consistency
      await this.syncWithStorage();
    } catch (error) {
      console.error('Error during activity cleanup:', error);
    }
  }

  /**
   * Sync activity tracker state with storage
   */
  private async syncWithStorage(): Promise<void> {
    try {
      // Get all users from storage and check their current status
      const allUsers = await storage.getAllUsers();

      for (const user of allUsers) {
        const sessionExists = this.activeSessions.has(user.id);
        const shouldBeOnline = sessionExists && this.getUserActivityStatus(user.id).isActive;

        // If storage shows user as online but no active session exists, mark as offline
        if (user.isOnline && !shouldBeOnline) {
          await storage.updateUserOnlineStatus(user.id, false);
          console.log(`Synced: marked ${user.username} as offline in storage`);
        }
      }
    } catch (error) {
      console.error('Error syncing with storage:', error);
    }
  }

  /**
   * Start the cleanup process
   */
  private startCleanupProcess(): void {
    console.log('Starting user activity cleanup process (30min timeout, 5min cleanup interval)');

    this.cleanupTimer = setInterval(() => {
      this.cleanupInactiveSessions();
    }, this.CLEANUP_INTERVAL);
  }

  /**
   * Stop the cleanup process
   */
  public stopCleanupProcess(): void {
    if (this.cleanupTimer) {
      clearInterval(this.cleanupTimer);
      this.cleanupTimer = null;
      console.log('User activity cleanup process stopped');
    }
  }

  /**
   * Force cleanup all sessions (useful for shutdown)
   */
  public async forceCleanupAll(): Promise<void> {
    console.log('Force cleaning up all user sessions...');

    for (const [userId] of this.activeSessions) {
      await this.markUserInactive(userId, 'forced_cleanup');
    }

    this.activeSessions.clear();
    console.log('All user sessions cleaned up');
  }

  /**
   * Force sync all users to correct status - marks all users without active sessions as offline
   */
  public async forceSyncAllUsers(): Promise<void> {
    try {
      console.log('🔄 Force syncing all user statuses...');
      const allUsers = await storage.getAllUsers();
      let correctedCount = 0;

      for (const user of allUsers) {
        const hasActiveSession = this.activeSessions.has(user.id);
        const activityStatus = this.getUserActivityStatus(user.id);

        // If user shows as online but has no active session or is not actually active
        if (user.isOnline && (!hasActiveSession || !activityStatus.isActive)) {
          await storage.updateUserOnlineStatus(user.id, false);
          console.log(`✓ Corrected: marked ${user.username} as offline (no active session)`);
          correctedCount++;
        }
      }

      console.log(`🔧 Force sync completed: corrected ${correctedCount} user statuses`);
    } catch (error) {
      console.error('Error in force sync:', error);
    }
  }
}

// Create and export the singleton instance
export const userActivityTracker = new UserActivityTracker();

/**
 * Middleware to track user activity on each authenticated request
 */
export const trackUserActivity = async (req: any, res: any, next: any) => {
  if (req.user?.id && req.user?.username) {
    await userActivityTracker.updateUserActivity(req.user.id);
  }
  next();
};

