@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@400;600;700&family=Inter:wght@300;400;500;600&family=JetBrains+Mono:wght@400;500&display=swap');

@tailwind base;
@tailwind components;
@tailwind utilities;

/* Enhanced theme transition support */
:root {
  --transition-duration: 0.6s;
  --transition-easing: cubic-bezier(0.4, 0, 0.2, 1);
  --theme-transition-properties: background-color, background-image, color, border-color, box-shadow, backdrop-filter, opacity;
}

/* Global smooth theme transitions */
* {
  transition: var(--theme-transition-properties) var(--transition-duration) var(--transition-easing);
}

/* Enhanced theme transition class for active transitions */
.theme-transitioning {
  pointer-events: none;
}

.theme-transitioning * {
  transition: all var(--transition-duration) var(--transition-easing) !important;
  will-change: background-color, color, border-color, box-shadow;
}

/* Responsive layout foundation */
html, body {
  overflow-x: hidden; /* Prevent horizontal scrollbars */
  width: 100%;
  min-width: 320px; /* Minimum mobile width */
}

/* Prevent layout shift during theme transitions */
body {
  overflow-x: hidden;
  font-family: Inter, system-ui, Avenir, Helvetica, Arial, sans-serif;
}

/* Dialog and Modal improvements for better scroll behavior */
.dialog-content-container {
  position: fixed !important;
  z-index: 50 !important;
  pointer-events: auto !important;
  touch-action: none !important; /* Prevent pull-to-refresh on mobile */
}

.dialog-overlay {
  position: fixed !important;
  inset: 0 !important;
  z-index: 50 !important;
  pointer-events: auto !important;
}

/* Prevent dialog close on scroll */
[data-radix-dialog-content] {
  touch-action: none !important;
  overscroll-behavior: contain !important;
}

/* Improve scrolling inside dialogs */
.dialog-scroll-area {
  overscroll-behavior: contain !important;
  -webkit-overflow-scrolling: touch !important;
}

/* Mobile responsive utilities */
@media (max-width: 640px) {
  .responsive-padding {
    padding-left: 16px !important;
    padding-right: 16px !important;
  }

  .mobile-hide {
    display: none !important;
  }

  .mobile-text-sm {
    font-size: 0.875rem !important;
  }

  .mobile-text-xs {
    font-size: 0.75rem !important;
  }

  .mobile-grid-1 {
    grid-template-columns: 1fr !important;
  }

  /* Better mobile dialog behavior */
  [data-radix-dialog-content] {
    max-height: 95vh !important;
    margin: 2.5vh auto !important;
    touch-action: pan-y !important;
  }
}

/* Tablet responsive utilities */
@media (min-width: 641px) and (max-width: 1023px) {
  .tablet-grid-2 {
    grid-template-columns: repeat(2, 1fr) !important;
  }
}

/* Desktop responsive utilities */
@media (min-width: 1024px) {
  .desktop-grid-3 {
    grid-template-columns: repeat(3, 1fr) !important;
  }
}

/* Content overflow prevention */
.prevent-overflow {
  max-width: 100%;
  overflow-x: hidden;
  word-wrap: break-word;
}

/* Mobile-first responsive grid */
.responsive-grid {
  display: grid;
  grid-template-columns: 1fr;
  gap: 1rem;
}

@media (min-width: 640px) {
  .responsive-grid {
    grid-template-columns: repeat(2, 1fr);
    gap: 1.5rem;
  }
}

@media (min-width: 1024px) {
  .responsive-grid {
    grid-template-columns: repeat(3, 1fr);
    gap: 2rem;
  }
}

/* Enhanced component-specific transitions */
.card, [class*="card"], .button, [role="button"], .input, .nav-item {
  transition: all var(--transition-duration) var(--transition-easing);
}

/* Gradient background transitions */
[style*="gradient"], [class*="gradient"] {
  transition: background var(--transition-duration) var(--transition-easing);
}

/* Theme preview animations */
.theme-preview {
  transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.theme-preview:hover {
  transform: translateY(-2px);
}

/* 3D Pin component animations */
@keyframes wave {
  0%, 100% {
    transform: translateY(0);
  }
  50% {
    transform: translateY(-10px);
  }
}

/* Theme application feedback animation */
.theme-applying {
  position: relative;
  overflow: hidden;
}

.theme-applying::before {
  content: '';
  position: absolute;
  top: 0;
  left: -100%;
  width: 100%;
  height: 100%;
  background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.2), transparent);
  animation: shimmer 1.5s ease-in-out infinite;
  z-index: 1;
}

@keyframes shimmer {
  0% {
    left: -100%;
  }
  100% {
    left: 100%;
  }
}

/* Enhanced page transition */
.page-transition-enter {
  opacity: 0;
  transform: translateY(20px);
}

.page-transition-enter-active {
  opacity: 1;
  transform: translateY(0);
  transition: opacity 0.6s ease, transform 0.6s ease;
}

/* Smooth category filter transitions */
.category-filter {
  transition: all 0.3s ease;
}

.category-filter:hover {
  transform: translateY(-1px);
}

/* Performance-optimized theme textures */
.theme-mystic-twilight {
  --texture-pattern: radial-gradient(circle at 20% 80%, rgba(168, 85, 247, 0.1) 0%, transparent 50%),
                     radial-gradient(circle at 80% 20%, rgba(139, 92, 246, 0.1) 0%, transparent 50%);
}

.theme-emerald-sunset {
  --texture-pattern: radial-gradient(circle at 30% 70%, rgba(0, 255, 135, 0.08) 0%, transparent 40%),
                     radial-gradient(circle at 70% 30%, rgba(16, 185, 129, 0.08) 0%, transparent 40%);
}

.theme-crimson-noir {
  --texture-pattern: radial-gradient(circle at 40% 60%, rgba(255, 59, 59, 0.12) 0%, transparent 50%),
                     radial-gradient(circle at 60% 40%, rgba(220, 38, 38, 0.08) 0%, transparent 50%);
}

.theme-cyber-ice {
  --texture-pattern: radial-gradient(circle at 25% 75%, rgba(0, 255, 255, 0.1) 0%, transparent 45%),
                     radial-gradient(circle at 75% 25%, rgba(6, 182, 212, 0.08) 0%, transparent 45%);
}

.theme-solar-dusk {
  --texture-pattern: radial-gradient(circle at 35% 65%, rgba(255, 165, 0, 0.12) 0%, transparent 50%),
                     radial-gradient(circle at 65% 35%, rgba(245, 158, 11, 0.08) 0%, transparent 50%);
}

.theme-galaxy-storm {
  --texture-pattern: radial-gradient(circle at 20% 80%, rgba(157, 78, 221, 0.15) 0%, transparent 55%),
                     radial-gradient(circle at 80% 20%, rgba(114, 9, 183, 0.12) 0%, transparent 55%);
}

.theme-neon-arcade {
  --texture-pattern: radial-gradient(circle at 30% 70%, rgba(255, 0, 128, 0.15) 0%, transparent 45%),
                     radial-gradient(circle at 70% 30%, rgba(199, 21, 133, 0.12) 0%, transparent 45%);
}

/* Apply textures to theme backgrounds with hardware acceleration */
body[class*="theme-"] {
  background-image: var(--texture-pattern);
  background-attachment: fixed;
  will-change: background-color, background-image;
  transform: translateZ(0); /* Force GPU acceleration */
}

/* Optimized card hover effects */
.card:hover, [class*="card"]:hover {
  transform: translateY(-2px) translateZ(0);
  box-shadow: 0 8px 25px rgba(0, 0, 0, 0.15);
  will-change: transform, box-shadow;
}

/* Smooth button interactions */
button:hover, [role="button"]:hover {
  transform: translateY(-1px) translateZ(0);
  will-change: transform;
}

/* Optimized gradient animations */
@keyframes gradient-shift {
  0%, 100% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
}

.gradient-animated {
  background-size: 200% 200%;
  animation: gradient-shift 8s ease infinite;
  will-change: background-position;
}

/* Performance-optimized glow effects */
.glow-effect {
  position: relative;
}

.glow-effect::after {
  content: '';
  position: absolute;
  inset: -2px;
  border-radius: inherit;
  background: inherit;
  filter: blur(8px);
  opacity: 0.3;
  z-index: -1;
  will-change: opacity;
}

.glow-effect:hover::after {
  opacity: 0.6;
}

/* Custom input styling for better number visibility */
input[type="number"] {
  -webkit-appearance: textfield;
  -moz-appearance: textfield;
  appearance: textfield;
}

input[type="number"]::-webkit-outer-spin-button,
input[type="number"]::-webkit-inner-spin-button {
  -webkit-appearance: none;
  margin: 0;
}

/* Ensure bet input fields show full numbers */
.bet-input-container {
