    background: linear-gradient(135deg, #ffffff 0%, #e5e5e5 25%, #ffffff 50%, #f0f0f0 75%, #ffffff 100%);
    -webkit-background-clip: text;
    -webkit-text-fill-color: transparent;
    background-clip: text;
    text-shadow: 0 1px 3px rgba(0, 0, 0, 0.3);
  }

  /* Enhanced Input Placeholder Styles */
  input::placeholder,
  textarea::placeholder {
    color: hsl(var(--muted-foreground) / 0.7);
    opacity: 1;
    transition: opacity 0.2s ease-in-out;
  }

  input:focus::placeholder,
  textarea:focus::placeholder {
    opacity: 0.5;
  }

  /* Enhanced Button Hover Effects */
  .btn-enhanced {
    position: relative;
    overflow: hidden;
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  }

  .btn-enhanced::before {
    content: '';
    position: absolute;
    top: 0;
    left: -100%;
    width: 100%;
    height: 100%;
    background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.1), transparent);
    transition: left 0.5s;
  }

  .btn-enhanced:hover::before {
    left: 100%;
  }

  /* Consistent Spacing Utilities */
  .spacing-xs { margin: 0.25rem; }
  .spacing-sm { margin: 0.5rem; }
  .spacing-md { margin: 1rem; }
  .spacing-lg { margin: 1.5rem; }
  .spacing-xl { margin: 2rem; }

  .gap-xs { gap: 0.25rem; }
  .gap-sm { gap: 0.5rem; }
  .gap-md { gap: 1rem; }
  .gap-lg { gap: 1.5rem; }
  .gap-xl { gap: 2rem; }

  /* Error State Styles */
  .error-container {
    border: 1px solid hsl(var(--destructive));
    background-color: hsl(var(--destructive) / 0.1);
    color: hsl(var(--destructive));
    border-radius: 0.5rem;
    padding: 0.75rem;
    margin: 0.5rem 0;
    animation: shake 0.5s ease-in-out;
  }

  .error-text {
    color: hsl(var(--destructive));
    font-size: 0.875rem;
    margin-top: 0.25rem;
  }

  .warning-container {
    border: 1px solid hsl(var(--warning));
    background-color: hsl(var(--warning) / 0.1);
    color: hsl(var(--warning));
    border-radius: 0.5rem;
    padding: 0.75rem;
    margin: 0.5rem 0;
  }

  .success-container {
    border: 1px solid hsl(var(--win));
    background-color: hsl(var(--win) / 0.1);
    color: hsl(var(--win));
    border-radius: 0.5rem;
    padding: 0.75rem;
    margin: 0.5rem 0;
    animation: fadeIn 0.5s ease-in-out;
  }

  @keyframes shake {
    0%, 100% { transform: translateX(0); }
    25% { transform: translateX(-5px); }
    75% { transform: translateX(5px); }
  }

  /* Consistent Focus States */
  .focus-enhanced:focus-visible {
    outline: 2px solid hsl(var(--ring));
    outline-offset: 2px;
    border-color: hsl(var(--ring));
    box-shadow: 0 0 0 2px hsl(var(--ring) / 0.2);
  }

  /* Responsive Grid Improvements */
  @media (max-width: 640px) {
    .responsive-grid {
      grid-template-columns: 1fr;
      gap: 0.75rem;
    }
  }

  @media (min-width: 641px) and (max-width: 1024px) {
    .responsive-grid {
      grid-template-columns: repeat(2, 1fr);
      gap: 1rem;
    }
  }

  @media (min-width: 1025px) {
    .responsive-grid {
      grid-template-columns: repeat(3, 1fr);
      gap: 1.5rem;
    }
  }

  /* Enhanced Card Hover Effects */
  .card-enhanced {
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  }

  .card-enhanced:hover {
    transform: translateY(-2px);
    box-shadow: 0 10px 25px rgba(0, 0, 0, 0.15);
  }

  /* Loading States */
  .loading-shimmer {
    background: linear-gradient(90deg, 
      hsl(var(--muted)) 25%, 
      hsl(var(--muted-foreground) / 0.1) 50%, 
      hsl(var(--muted)) 75%);
    background-size: 200% 100%;
    animation: shimmer 2s infinite;
  }

  .loading-skeleton {
    background-color: hsl(var(--muted));
    border-radius: 0.25rem;
    animation: pulse 2s infinite;
  }

  /* Mobile Optimizations */
  @media (max-width: 640px) {
    /* Increase touch targets on mobile */
    button, [role="button"], input[type="button"], input[type="submit"] {
      min-height: 44px;
      min-width: 44px;
    }

    /* Improve text readability */
    body {
      -webkit-text-size-adjust: 100%;
      text-size-adjust: 100%;
    }

    /* Better form controls */
    input, textarea, select {
      font-size: 16px; /* Prevents zoom on iOS */
    }

    /* Reduce motion for users who prefer it */
    @media (prefers-reduced-motion: reduce) {
      *, *::before, *::after {
        animation-duration: 0.01ms !important;
        animation-iteration-count: 1 !important;
        transition-duration: 0.01ms !important;
      }
    }
  }

  /* Tablet optimizations */
  @media (min-width: 641px) and (max-width: 1024px) {
    .tablet-optimized {
      padding: 1rem;
    }
  }

  /* High DPI displays */
  @media (-webkit-min-device-pixel-ratio: 2), (min-resolution: 192dpi) {
    .crisp-edges {
      image-rendering: crisp-edges;
      image-rendering: -webkit-optimize-contrast;
    }
  }

  /* Dark mode preferences */
  @media (prefers-color-scheme: dark) {
    :root {
      color-scheme: dark;
    }
  }

  /* Accessibility improvements */
  @media (prefers-contrast: high) {
    .enhanced-contrast {
      border-width: 2px;
      filter: contrast(1.2);
    }
  }

  /* Print styles */
  @media print {
    .no-print {
      display: none !important;
    }

    .print-block {
      display: block !important;
    }

    body {
      background: white !important;
      color: black !important;
    }
  }

  /* Safe area support for notched devices */
  .safe-area-inset {
    padding-top: env(safe-area-inset-top);
    padding-right: env(safe-area-inset-right);
    padding-bottom: env(safe-area-inset-bottom);
    padding-left: env(safe-area-inset-left);
  }

  /* Smooth scrolling with momentum */
  .momentum-scroll {
    -webkit-overflow-scrolling: touch;
    overflow-scrolling: touch;
  }

  /* Enhanced Mystic Twilight Effects */
