  .theme-shiny-black-white nav,
  .theme-shiny-black-white header {
    background: linear-gradient(180deg, #1e293b 0%, #0f172a 50%, #1e293b 100%);
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
