@layer base {
  * {
    @apply border-border;
  }

  body {
    @apply font-sans bg-[hsl(var(--background))] text-[hsl(var(--foreground))];
    transition: background-color 0.3s ease, color 0.3s ease, border-color 0.3s ease;
  }

  h1, h2, h3, h4, h5, h6 {
    @apply font-heading;
  }

  /* Ensure text visibility across all themes */
  * {
    color: inherit;
  }

  /* Base text elements inherit from theme */
  p, span, div, label, a, small, strong, em, li, td, th,
  .text-sm, .text-xs, .text-lg, .text-xl {
    color: inherit;
  }

  /* Form elements respect theme colors */
  input, textarea, select {
    color: hsl(var(--foreground));
    background-color: hsl(var(--input));
    border-color: hsl(var(--border));
  }

  input::placeholder, textarea::placeholder {
    color: hsl(var(--muted-foreground));
    opacity: 0.7;
  }

  /* Focus states */
  input:focus, textarea:focus, select:focus {
    border-color: hsl(var(--ring));
    outline: none;
  }

  /* Button states */
  button, [role="button"] {
    transition: opacity 0.2s ease;
  }

  button:hover, [role="button"]:hover, a:hover {
    opacity: 0.8;
  }

  /* Override problematic dark text classes that might conflict with themes */
  .text-black, .text-gray-900, .text-slate-900, .text-zinc-900, .text-neutral-900 {
    color: hsl(var(--foreground)) !important;
  }

  /* State colors */
  .text-destructive, .error {
    color: hsl(var(--destructive)) !important;
  }

  /* Theme-specific styles that ensure proper inheritance */
  .app-wrapper, body {
    transition: background-color 0.3s ease, color 0.3s ease, border-color 0.3s ease;
  }
}

.bg-background-light {
  background-color: hsl(var(--background-light));
}

.bg-background-darker {
  background-color: hsl(var(--background-darker));
}

.bg-surface {
  background-color: hsl(var(--muted));
}

.border-background-light {
  border-color: hsl(var(--background-light));
}

.border-background-darker {
  border-color: hsl(var(--background-darker));
}

.bg-win {
  background-color: hsl(var(--win));
}

.bg-loss {
  background-color: hsl(var(--loss));
}

.text-win {
  color: hsl(var(--win));
}

.text-loss {
  color: hsl(var(--loss));
}

.bg-accent-gold {
  background-color: hsl(var(--accent-gold));
}

.text-accent-gold {
  color: hsl(var(--accent-gold));
}

.bg-warning {
  background-color: hsl(var(--warning));
