                              <Play className="h-4 w-4 mr-1" />
                              Play
                            </Button>
                            <Button
                              variant="outline"
                              size="sm"
                              onClick={() => handleViewCode(game)}
                            >
                              <Edit className="h-4 w-4 mr-1" />
