import { useState } from "react";
import { MainLayout } from "@/components/layout/MainLayout";
import { Check, DollarSign } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { Currency } from "@shared/schema";

const currencies = [
  {
    id: Currency.USD,
    name: "US Dollar",
