import React, { useState, useEffect, useRef } from 'react';
import { useParams, useLocation } from 'wouter';
import { MainLayout } from '@/components/layout/MainLayout';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { ArrowLeft, Play, Coins, TrendingUp, Info } from 'lucide-react';
import { FlexibleBetInput } from '@/components/ui/flexible-bet-input';
import { get, post } from '@/lib/api';
import { useAuth } from '@/hooks/use-auth';
import { useWallet } from '@/hooks/use-wallet';
import { toast } from '@/hooks/use-toast';

interface CustomGame {
  id: number;
  name: string;
  type: string;
  htmlContent: string;
  winChance: number;
  maxMultiplier: number;
  minBet: string;
  maxBet: string;
  description?: string;
  isActive: boolean;
  createdAt: string;
  createdBy: number;
}

export default function HtmlGamePage() {
  const { user } = useAuth();
  const { balance: userBalance, currency: userCurrency, refetchBalance } = useWallet();
  const [, setLocation] = useLocation();
  const params = useParams();
  const gameId = parseInt(params.id as string);

  const [game, setGame] = useState<CustomGame | null>(null);
  const [loading, setLoading] = useState(true);
  const [betAmount, setBetAmount] = useState(10);
  const [isPlaying, setIsPlaying] = useState(false);
  const [gameHistory, setGameHistory] = useState<any[]>([]);
  const [enhancedHtmlContent, setEnhancedHtmlContent] = useState('');
  const gameIframeRef = useRef<HTMLIFrameElement>(null);

  useEffect(() => {
    if (gameId && !isNaN(gameId)) {
      fetchGame();
    } else {
      toast({
        title: "Invalid Game ID",
        description: "The game ID provided is not valid.",
        variant: "destructive",
      });
      setLocation('/games');
    }
  }, [gameId]);

  useEffect(() => {
    if (game) {
      const enhanced = enhanceHtmlGameContent(game.htmlContent);
      setEnhancedHtmlContent(enhanced);
      setBetAmount(Math.max(Number(game.minBet), 10));
    }
  }, [game]);

  const fetchGame = async () => {
    try {
      setLoading(true);
      const foundGame = await get(`/api/games/custom/${gameId}`);

      if (!foundGame) {
        toast({
          title: "Game Not Found",
          description: "The requested game could not be found.",
          variant: "destructive",
        });
        setLocation('/games');
        return;
      }

      const gameData = await foundGame.json();
      setGame(gameData);
    } catch (error) {
      console.error('Error fetching game:', error);
      toast({
        title: "Error",
        description: "Failed to load game. Please try again.",
        variant: "destructive",
      });
      setLocation('/games');
    } finally {
      setLoading(false);
    }
  };

  const enhanceHtmlGameContent = (originalHtml: string) => {
    const casinoScript = `
      <script>
        // Casino integration bridge for HTML games
        window.casinoAPI = {
          gameId: ${gameId},
          userBalance: ${userBalance},
          currency: '${userCurrency}',
          minBet: ${game?.minBet || 1},
          maxBet: ${game?.maxBet || 1000},
          winChance: ${game?.winChance || 50},
          maxMultiplier: ${game?.maxMultiplier || 2.0},

          // Place a bet and process game result
          async placeBet(betAmount, gameResult = null) {
            try {
              // Validate bet amount
              if (betAmount < this.minBet || betAmount > this.maxBet) {
                throw new Error(\`Bet amount must be between \${this.minBet} and \${this.maxBet}\`);
              }

              if (betAmount > this.userBalance) {
                throw new Error('Insufficient balance');
              }

              // Send bet to parent window
              window.parent.postMessage({
                type: 'PLACE_BET',
                gameId: this.gameId,
                betAmount: betAmount,
                gameResult: gameResult
              }, '*');

              return true;
            } catch (error) {
              console.error('Casino API Error:', error);
              window.parent.postMessage({
                type: 'GAME_ERROR',
                error: error.message
              }, '*');
              return false;
            }
          },

          // Update balance display (called by parent)
          updateBalance(newBalance) {
            this.userBalance = newBalance;
            const balanceElements = document.querySelectorAll('.casino-balance');
            balanceElements.forEach(el => {
              el.textContent = \`\${newBalance} \${this.currency}\`;
            });
          },

          // Utility functions for game developers
          generateRandomResult(winChance = this.winChance) {
            return Math.random() * 100 < winChance;
          },

          calculatePayout(betAmount, multiplier) {
            return Math.floor(betAmount * multiplier);
          },

          // Display current balance
          getCurrentBalance() {
            return this.userBalance;
          }
        };

        // Auto-inject balance display if elements exist
        document.addEventListener('DOMContentLoaded', function() {
          const balanceElements = document.querySelectorAll('.casino-balance');
          balanceElements.forEach(el => {
            el.textContent = \`\${window.casinoAPI.userBalance} \${window.casinoAPI.currency}\`;
          });

          // Add click handlers for bet buttons
          const betButtons = document.querySelectorAll('.casino-bet-button');
          betButtons.forEach(btn => {
            btn.addEventListener('click', function() {
              const betAmount = parseFloat(this.dataset.betAmount) || 10;
              window.casinoAPI.placeBet(betAmount);
            });
          });
        });

        console.log('Casino API initialized for game ID:', window.casinoAPI.gameId);
      </script>

      <style>
        .casino-balance {
          font-weight: bold;
          color: #10b981;
          font-size: 1.1em;
        }

        .casino-bet-button {
          background: linear-gradient(135deg, #3b82f6, #1d4ed8);
          color: white;
          border: none;
          padding: 8px 16px;
          border-radius: 6px;
          cursor: pointer;
          font-weight: 600;
          transition: all 0.2s;
        }

        .casino-bet-button:hover {
          background: linear-gradient(135deg, #2563eb, #1e40af);
          transform: translateY(-1px);
        }

        .casino-bet-button:disabled {
          opacity: 0.5;
          cursor: not-allowed;
          transform: none;
        }

        .casino-game-container {
          max-width: 100%;
          margin: 0 auto;
          padding: 20px;
          background: linear-gradient(135deg, #1f2937, #111827);
          border-radius: 12px;
          color: white;
        }
      </style>`;

    // Inject the enhanced HTML content
    return `
      <!DOCTYPE html>
      <html lang="en">
      <head>
        <meta charset="UTF-8">
        <meta name="viewport" content="width=device-width, initial-scale=1.0">
        <title>${game?.name || 'Custom Game'}</title>
        ${casinoScript}
      </head>
      <body>
        ${originalHtml}
      </body>
      </html>
    `;
  };
  // Handle messages from iframe (game results)
  useEffect(() => {
    const handleMessage = async (event: MessageEvent) => {
      if (event.data.type === 'PLACE_BET') {
        await handleIframeBet(event.data);
      } else if (event.data.type === 'GAME_ERROR') {
        toast({
          title: "Game Error",
          description: event.data.error,
          variant: "destructive",
        });
      }
    };

    window.addEventListener('message', handleMessage);
    return () => window.removeEventListener('message', handleMessage);
  }, []);

  const handleIframeBet = async (data: any) => {
    try {
      setIsPlaying(true);

      // Process the bet through the existing casino system
      const response = await post('/api/games/html-game/bet', {
        gameId: data.gameId,
        betAmount: data.betAmount,
        gameResult: data.gameResult
      });

      if (response.ok) {
        const result = await response.json();

        // Update balance
        await refetchBalance();

        // Send updated balance to iframe
        if (gameIframeRef.current?.contentWindow) {
          gameIframeRef.current.contentWindow.postMessage({
            type: 'BALANCE_UPDATE',
            balance: userBalance,
            gameResult: result
          }, '*');
        }

        // Show result toast
        toast({
          title: result.won ? "You Won!" : "Try Again!",
          description: result.won 
            ? `You won ${result.winAmount} ${userCurrency} (${result.multiplier}x)`
            : `Better luck next time!`,
          variant: result.won ? "default" : "destructive",
        });

      } else {
        const error = await response.json();
        toast({
          title: "Bet Failed",
          description: error.message,
          variant: "destructive",
        });
      }
    } catch (error) {
      console.error('Error processing iframe bet:', error);
      toast({
        title: "Error",
        description: "Failed to process bet",
        variant: "destructive",
      });
    } finally {
      setIsPlaying(false);
    }
  };

  // Handle manual betting (from the betting interface outside the game)
  const handlePlaceHtmlGameBet = async () => {
    if (!game || isPlaying) return;

    try {
      setIsPlaying(true);

      const response = await post('/api/games/html-game/bet', {
        gameId: gameId,
        betAmount: betAmount,
        gameResult: null // Let the system determine the outcome
      });

      if (response.ok) {
        const result = await response.json();

        // Update balance
        await refetchBalance();

        // Send result to iframe if needed
        if (gameIframeRef.current?.contentWindow) {
          gameIframeRef.current.contentWindow.postMessage({
            type: 'GAME_RESULT',
            result: result
          }, '*');
        }

        // Show result toast
        toast({
          title: result.won ? "You Won!" : "Try Again!",
          description: result.won 
            ? `You won ${result.winAmount} ${userCurrency} (${result.multiplier}x)`
            : `Better luck next time!`,
          variant: result.won ? "default" : "destructive",
        });

      } else {
        const error = await response.json();
        toast({
          title: "Bet Failed",
          description: error.message,
          variant: "destructive",
        });
      }
    } catch (error) {
      console.error('Error placing bet:', error);
      toast({
        title: "Error",
        description: "Failed to place bet",
        variant: "destructive",
      });
    } finally {
      setIsPlaying(false);
    }
  };

  if (loading) {
    return (
      <MainLayout>
        <div className="container mx-auto px-4 py-8">
          <div className="flex justify-center items-center h-64">
            <div className="text-lg">Loading game...</div>
          </div>
        </div>
      </MainLayout>
    );
  }

  if (!game) {
    return (
      <MainLayout>
        <div className="container mx-auto px-4 py-8">
          <div className="flex justify-center items-center h-64">
            <div className="text-lg text-red-600">Game not found</div>
          </div>
        </div>
      </MainLayout>
    );
  }

  return (
    <MainLayout>
      <div className="container mx-auto px-4 py-8">
        {/* Header */}
        <div className="flex items-center gap-4 mb-6">
          <Button
            variant="outline"
            size="sm"
            onClick={() => setLocation('/games')}
            className="flex items-center gap-2"
          >
            <ArrowLeft className="h-4 w-4" />
            Back to Games
          </Button>
          <h1 className="text-3xl font-bold">{game.name}</h1>
          <Badge variant="secondary">{game.type.toUpperCase()}</Badge>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Game Area */}
          <div className="lg:col-span-2 space-y-6">
            {/* Betting Interface */}
            <Card>
              <CardHeader>
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-2">
                    <Coins className="h-5 w-5 text-yellow-500" />
                    <CardTitle>Place Your Bet</CardTitle>
                  </div>
                  <div className="text-right">
                    <div className="text-sm text-muted-foreground">Balance</div>
                    <div className="text-lg font-semibold">{userBalance} {userCurrency}</div>
                  </div>
                </div>
              </CardHeader>
              <CardContent>
                <div className="space-y-4">
                  <FlexibleBetInput
                    value={betAmount}
                    onChange={setBetAmount}
                    disabled={isPlaying}
                    currency={userCurrency}
                    balance={userBalance}
                    minBet={Number(game.minBet)}
                    maxBet={Number(game.maxBet)}
                    className="max-w-md mx-auto"
                  />

                  <Button
                    onClick={handlePlaceHtmlGameBet}
                    disabled={isPlaying || betAmount < Number(game.minBet) || betAmount > userBalance || !user}
                    className="w-full"
                    size="lg"
                  >
                    {isPlaying ? (
                      <>
                        <Play className="mr-2 h-4 w-4 animate-spin" />
                        Playing...
                      </>
                    ) : (
                      <>
                        <Play className="mr-2 h-4 w-4" />
                        Play for {betAmount} {userCurrency}
                      </>
                    )}
                  </Button>
                </div>
              </CardContent>
            </Card>

            {/* Game iframe */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Play className="h-5 w-5" />
                  Game Area
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="w-full">
                  <iframe
                    key={enhancedHtmlContent} // Force re-render when content changes
                    srcDoc={enhancedHtmlContent}
                    className="w-full h-96 border border-gray-300 rounded-lg bg-gray-900"
                    title={game.name}
                    sandbox="allow-scripts allow-same-origin"
                    ref={gameIframeRef}
                  />
                </div>
              </CardContent>
            </Card>
          </div>

          {/* Sidebar */}
          <div className="space-y-6">
            {/* Game Info */}
            <Card>
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Info className="h-5 w-5" />
                  Game Info
                </CardTitle>
              </CardHeader>
              <CardContent className="space-y-3">
                {game.description && (
                  <p className="text-sm text-muted-foreground">{game.description}</p>
                )}
                <div className="space-y-2 text-sm">
                  <div className="flex justify-between">
                    <span>Win Chance:</span>
                    <span className="font-semibold text-green-600">{game.winChance}%</span>
                  </div>
                  <div className="flex justify-between">
                    <span>Max Multiplier:</span>
                    <span className="font-semibold text-blue-600">{game.maxMultiplier}x</span>
                  </div>
                  <div className="flex justify-between">
                    <span>Bet Range:</span>
                    <span className="font-semibold">{game.minBet} - {game.maxBet}</span>
                  </div>
                </div>
              </CardContent>
            </Card>

            {/* Recent Games */}
            {gameHistory.length > 0 && (
              <Card>
                <CardHeader>
                  <CardTitle className="flex items-center gap-2">
                    <TrendingUp className="h-5 w-5" />
                    Recent Games
                  </CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="space-y-2">
                    {gameHistory.slice(0, 5).map((entry) => (
                      <div
                        key={entry.id}
                        className={`flex justify-between items-center p-2 rounded text-sm ${
                          entry.won ? 'bg-green-50 text-green-800' : 'bg-red-50 text-red-800'
                        }`}
                      >
                        <div>
                          <div className="font-semibold">
                            {entry.won ? `+${entry.winAmount.toFixed(2)}` : `-${entry.betAmount}`} {entry.currency}
                          </div>
                          <div className="text-xs opacity-75">
                            {entry.won ? `${entry.multiplier}x` : 'Lost'}
                          </div>
                        </div>
                        <div className="text-xs opacity-75">
                          {entry.timestamp.toLocaleTimeString()}
                        </div>
                      </div>
                    ))}
                  </div>
                </CardContent>
              </Card>
            )}
          </div>
        </div>
      </div>
    </MainLayout>
  );
}

client/src/pages/leaderboard-page.tsx.content:
import { useState, useEffect } from "react";
import { MainLayout } from "@/components/layout/MainLayout";
import { TrendingUp, Medal, Award, Clock, User, DollarSign } from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { formatCurrency } from "@/lib/game-utils";

interface Winner {
  id: number;
  userId: number;
  username: string;
  gameType: string;
  betAmount: string;
  winAmount: string;
  multiplier: number;
  currency: string;
  isWin: boolean;
  createdAt: string;
}

export default function LeaderboardPage() {
  const [winners, setWinners] = useState<Winner[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const { toast } = useToast();

  useEffect(() => {
    async function fetchWinners() {
      try {
        const response = await fetch('/api/games/winners?limit=20');
        if (!response.ok) {
          throw new Error('Failed to fetch leaderboard data');
        }
        const data = await response.json();
        setWinners(data);
      } catch (error) {
        toast({
          title: "Error",
          description: "Failed to load leaderboard data",
          variant: "destructive",
        });
        console.error(error);
      } finally {
        setIsLoading(false);
      }
    }

    fetchWinners();
    // Refresh winners every 60 seconds
    const interval = setInterval(() => {
      fetchWinners();
    }, 60000);

    return () => clearInterval(interval);
  }, [toast]);

  const getGameIcon = (gameType: string) => {
    switch (gameType) {
      case 'slots':
        return '🎰';
      case 'dice':
        return '🎲';
      case 'plinko':
        return '⚾';
      case 'crash':
        return '📈';
      default:
        return '🎮';
    }
  };

  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    return new Intl.DateTimeFormat('en-US', {
      month: 'short',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    }).format(date);
  };

  return (
    <MainLayout>
      <div className="p-6 max-w-6xl mx-auto">
        <div className="flex items-center mb-6">
          <TrendingUp className="h-8 w-8 text-primary mr-3" />
          <h1 className="text-3xl font-bold">Leaderboard</h1>
        </div>

        <div className="bg-card rounded-lg p-6 shadow-lg animate-fadeIn">
          <h2 className="text-xl font-semibold mb-6 flex items-center">
            <Medal className="h-5 w-5 text-yellow-400 mr-2" />
            Recent Winners
          </h2>

          {isLoading ? (
            <div className="flex justify-center py-12">
              <div className="animate-spin h-8 w-8 border-4 border-primary border-t-transparent rounded-full"></div>
            </div>
          ) : winners.length === 0 ? (
            <div className="text-center py-12">
              <Award className="h-12 w-12 text-gray-400 mx-auto mb-3" />
              <p className="text-gray-400">No winners yet. Be the first one!</p>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead>
                  <tr className="border-b border-border text-left text-gray-400">
                    <th className="pb-3 pl-2">Rank</th>
                    <th className="pb-3">
                      <div className="flex items-center">
                        <User className="h-4 w-4 mr-1" />
                        Player
                      </div>
                    </th>
                    <th className="pb-3">
                      <div className="flex items-center">
                        Game
                      </div>
                    </th>
                    <th className="pb-3">
                      <div className="flex items-center">
                        <DollarSign className="h-4 w-4 mr-1" />
                        Win Amount
                      </div>
                    </th>
                    <th className="pb-3">
                      <div className="flex items-center">
                        Multiplier
                      </div>
                    </th>
                    <th className="pb-3">
                      <div className="flex items-center">
                        <Clock className="h-4 w-4 mr-1" />
                        When
                      </div>
                    </th>
                  </tr>
                </thead>
                <tbody>
                  {winners.map((winner, index) => (
                    <tr 
                      key={winner.id} 
                      className="border-b border-border hover:bg-background-light transition-colors cursor-pointer"
                    >
                      <td className="py-3 pl-2">
                        {index === 0 ? (
                          <span className="flex items-center justify-center w-6 h-6 bg-yellow-500 rounded-full text-black font-bold">1</span>
                        ) : index === 1 ? (
                          <span className="flex items-center justify-center w-6 h-6 bg-gray-400 rounded-full text-black font-bold">2</span>
                        ) : index === 2 ? (
                          <span className="flex items-center justify-center w-6 h-6 bg-amber-700 rounded-full text-black font-bold">3</span>
                        ) : (
                          index + 1
                        )}
                      </td>
                      <td className="py-3 font-medium">{winner.username}</td>
                      <td className="py-3">
                        <div className="flex items-center">
                          <span className="mr-2">{getGameIcon(winner.gameType)}</span>
                          <span className="capitalize">{winner.gameType}</span>
                        </div>
                      </td>
                      <td className="py-3 text-green-500 font-medium">
                        {formatCurrency(parseFloat(winner.winAmount), winner.currency)}
                      </td>
                      <td className="py-3">
                        {winner.multiplier}x
                      </td>
                      <td className="py-3 text-gray-400">
                        {formatDate(winner.createdAt)}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>

        <div className="mt-6 p-4 bg-background rounded-lg border border-border">
          <h3 className="text-sm font-medium mb-2 text-gray-400">ABOUT THE LEADERBOARD</h3>
          <p className="text-sm text-gray-400">
            The leaderboard shows the most recent big winners from all casino games.
            Win big to get your name on the leaderboard!
          </p>
        </div>
      </div>
    </MainLayout>
  );
}

client/src/pages/new-auth-page.tsx.content:
import { useState, useEffect } from "react";
import { useLocation } from "wouter";
import { useAuth } from "@/hooks/use-auth";
import { motion } from "framer-motion";
import { AuthLanguageSelector } from "@/components/ui/language-selector";
import { useTranslation } from "@/providers/LanguageProvider";

const projectShadowLogo = "/assets/new-logo.png";

// Stars background component
function StarsBackground() {
  useEffect(() => {
    const stars: HTMLDivElement[] = [];
    const starsContainer = document.querySelector('.stars-container');

    if (starsContainer) {
      for (let i = 0; i < 500; i++) {
        const star = document.createElement('div');
        star.className = 'star';
        const size = Math.random() * 2 + 1;
        star.style.width = `${size}px`;
        star.style.height = `${size}px`;
        star.style.top = `${Math.random() * 100}%`;
        star.style.left = `${Math.random() * 100}%`;
        star.style.animationDelay = `${Math.random() * 10}s, ${Math.random() * 10}s`;
        starsContainer.appendChild(star);
        stars.push(star);
      }
    }

    return () => {
      stars.forEach(star => star.remove());
    };
  }, []);

  return <div className="stars-container fixed top-0 left-0 w-full h-full overflow-hidden pointer-events-none z-0" />;
}

export default function NewAuthPage() {
  const [formType, setFormType] = useState<"login" | "register">("login");
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const { login, register, isLoading, error, user } = useAuth();
  const [, navigate] = useLocation();
  const { t } = useTranslation();

  // Redirect if already logged in
  useEffect(() => {
    if (user) {
      navigate('/');
    }
  }, [user, navigate]);

  // Login form state
  const [loginData, setLoginData] = useState({
    username: "",
    password: ""
  });

  // Register form state
  const [registerData, setRegisterData] = useState({
    username: "",
    email: "",
    password: "",
    phone: ""
  });

  // Set error messages from auth context
  useEffect(() => {
    if (error) {
      setErrorMessage(error);
    }
  }, [error]);

  // Handle login form submission
  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMessage(null);

    try {
      await login(loginData);
    } catch (error) {
      // Error handling is done in auth context
    }
  };

  // Handle register form submission
  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMessage(null);

    try {
      await register(registerData);
    } catch (error) {
      // Error handling is done in auth context
    }
  };

  return (
    <>
      <style>{`
        .stars-container .star {
          position: absolute;
          background: rgba(255, 255, 255, 0.8);
          border-radius: 50%;
          animation: twinkle 5s infinite, move 20s linear infinite;
          will-change: transform;
        }
        @keyframes twinkle {
          0% { opacity: 0.3; }
          50% { opacity: 0.8; }
          100% { opacity: 0.3; }
        }
        @keyframes move {
          0% { transform: translate(0, 0); }
          100% { transform: translate(50vw, 50vh); }
        }
        @keyframes slideIn {
          to { transform: translateY(0); opacity: 1; }
        }
        @keyframes fadeIn {
          to { opacity: 1; }
        }
        .new-auth-container {
          background: linear-gradient(135deg, #000, #1a0033);
        }
        .login-section {
          transform: translateY(20px);
          opacity: 0;
          animation: slideIn 0.5s ease-out forwards;
        }
        .info-section {
          opacity: 0;
          animation: fadeIn 0.5s ease-out 0.2s forwards;
        }
        .floating-logo {
          position: absolute;
          top: 20px;
          left: 20px;
          width: 35px;
          height: auto;
          transition: transform 0.3s ease;
          z-index: 10;
        }
        .floating-logo:hover {
          transform: rotate(10deg) scale(1.1);
        }
        .auth-input {
          background: #333 !important;
          border: none !important;
          color: #fff !important;
          transition: background 0.3s ease;
        }
        .auth-input:focus {
          background: #444 !important;
        }
        .auth-button {
          background: #6b48ff !important;
          transition: transform 0.3s ease, background 0.3s ease;
        }
        .auth-button:hover {
          transform: scale(1.05);
          background: #8a6aff !important;
        }
      `}</style>

      <div className="new-auth-container min-h-screen flex items-center justify-center overflow-hidden relative">
        <StarsBackground />

        <img 
          src={projectShadowLogo} 
          alt="Project Shadow Casino Logo" 
          className="floating-logo"
        />

        {/* Language Selector */}
        <div className="absolute top-5 right-5 z-20">
          <AuthLanguageSelector />
        </div>

        <div className="flex justify-between items-center w-4/5 max-w-6xl relative z-10 max-md:flex-col max-md:w-11/12">
          <motion.div
            initial={{ opacity: 0, x: -50 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.6 }}
            className="login-section bg-black/70 p-8 rounded-xl w-2/5 max-md:w-full max-md:mb-8 flex flex-col items-center justify-center"
          >
            <h2 className="text-white text-2xl mb-6 text-center w-full">
              {formType === "login" ? t('auth.login') : t('auth.register')}
            </h2>

            <div className="w-4/5">
              {formType === "login" ? (
                <form onSubmit={handleLogin} className="space-y-4 w-full flex flex-col items-center">
                  <div className="w-full">
                    <label className="text-white block mb-1 text-left">
                      {t('auth.username')}
                    </label>
                    <input 
                      type="text"
                      className="auth-input w-full p-2 rounded"
                      placeholder={t('auth.username')}
                      value={loginData.username}
                      onChange={(e) => setLoginData({...loginData, username: e.target.value})}
                      required
                    />
                  </div>
                  <div className="w-full">
                    <label className="text-white block mb-1 text-left">
                      {t('auth.password')}
                    </label>
                    <input 
                      type="password"
                      className="auth-input w-full p-2 rounded"
                      placeholder={t('auth.password')}
                      value={loginData.password}
                      onChange={(e) => setLoginData({...loginData, password: e.target.value})}
                      required
                    />
                  </div>
                  <button 
                    type="submit" 
                    className="auth-button text-white px-6 py-2 rounded w-2/3"
                    disabled={isLoading}
                  >
                    {isLoading ? t('ui.loading') : t('auth.signin')}
                  </button>
                </form>
              ) : (
                <form onSubmit={handleRegister} className="space-y-4 w-full flex flex-col items-center">
                  <div className="w-full">
                    <label className="text-white block mb-1 text-left">
                      {t('auth.username')}
                    </label>
                    <input 
                      type="text"
                      className="auth-input w-full p-2 rounded"
                      placeholder={t('auth.username')}
                      value={registerData.username}
                      onChange={(e) => setRegisterData({...registerData, username: e.target.value})}
                      required
                    />
                  </div>
                  <div className="w-full">
                    <label className="text-white block mb-1 text-left">
                      {t('auth.email')}
                    </label>
                    <input 
                      type="email"
                      className="auth-input w-full p-2 rounded"
                      placeholder={t('auth.email')}
                      value={registerData.email}
                      onChange={(e) => setRegisterData({...registerData, email: e.target.value})}
                      required
                    />
                  </div>
                  <div className="w-full">
                    <label className="text-white block mb-1 text-left">
                      {t('auth.password')}
                    </label>
                    <input 
                      type="password"
                      className="auth-input w-full p-2 rounded"
                      placeholder={t('auth.password')}
                      value={registerData.password}
                      onChange={(e) => setRegisterData({...registerData, password: e.target.value})}
                      required
                    />
                  </div>
                  <div className="w-full">
                    <label className="text-white block mb-1 text-left">
                      {t('auth.phone')}
                    </label>
                    <input 
                      type="tel"
                      className="auth-input w-full p-2 rounded"
                      placeholder={t('auth.phone')}
                      value={registerData.phone}
                      onChange={(e) => setRegisterData({...registerData, phone: e.target.value})}
                      required
                    />
                  </div>
                  <button 
                    type="submit" 
                    className="auth-button text-white px-6 py-2 rounded w-2/3"
                    disabled={isLoading}
                  >
                    {isLoading ? t('ui.loading') : t('auth.signup')}
                  </button>
                </form>
              )}

              {errorMessage && (
                <div className="text-red-500 text-center mt-4">
                  {errorMessage}
                </div>
              )}

              <p className="text-white/70 text-sm text-center mt-6">
                {formType === "login" ? (
                  <>
                    {t('auth.switchToRegister')}{' '}
                    <button
                      type="button"
                      onClick={() => setFormType("register")}
                      className="text-white underline hover:no-underline"
                    >
                      {t('auth.signup')}
                    </button>
                  </>
                ) : (
                  <>
                    {t('auth.switchToLogin')}{' '}
                    <button
                      type="button"
                      onClick={() => setFormType("login")}
                      className="text-white underline hover:no-underline"
                    >
                      {t('auth.signin')}
                    </button>
                  </>
                )}
              </p>
            </div>
          </motion.div>

          <motion.div
            initial={{ opacity: 0, x: 50 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.6, delay: 0.2 }}
            className="info-section text-white text-left w-1/2 max-md:w-full max-md:text-center"
          >
            <h1 className="text-6xl font-bold mb-4">{t('auth.welcome')}</h1>
            <p className="text-2xl text-white/70">{t('auth.subtitle')}</p>
          </motion.div>
        </div>
      </div>
    </>
  );
}

