import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { queryClient, apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { motion, AnimatePresence } from "framer-motion";
import { ArrowLeft, Plus, Minus, Circle } from "lucide-react";
import { FlexibleBetInput } from "@/components/ui/flexible-bet-input";
import { Link } from "wouter";

export default function Plinko() {
  const [betAmount, setBetAmount] = useState(10);
  const [lastResult, setLastResult] = useState<any>(null);
  const [ballPosition, setBallPosition] = useState<number | null>(null);
  const { toast } = useToast();

  const { data: user } = useQuery({
    queryKey: ["/api/user"],
  });

  const { data: balance } = useQuery({
    queryKey: ["/api/wallet/balance"],
  });

  const dropMutation = useMutation({
    mutationFn: async () => {
      const response = await apiRequest("POST", "/api/plinko/drop", { bet: betAmount });
      return response.json();
    },
    onSuccess: (data) => {
      setLastResult(data);
      setBallPosition(data.bucket);
      queryClient.invalidateQueries({ queryKey: ["/api/user"] });
      queryClient.invalidateQueries({ queryKey: ["/api/games"] });

      if (data.result === 'win') {
        toast({
          title: "🎉 You Win!",
          description: `You won ${data.payout} credits!`,
          className: "bg-green-600 text-white",
        });
      } else {
        toast({
          title: "Try Again",
          description: "Better luck next drop!",
          variant: "destructive",
        });
      }
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const handleDrop = () => {
    if (!user || user.balance < betAmount) {
      toast({
        title: "Insufficient Balance",
        description: "You don't have enough credits to place this bet.",
        variant: "destructive",
      });
      return;
    }
    setBallPosition(null);
    dropMutation.mutate();
  };

  const multipliers = [16.0, 9.0, 2.0, 1.4, 1.4, 1.2, 1.0, 0.5, 0.2, 0.2, 0.2, 1.0, 1.2, 1.4, 1.4, 2.0, 9.0, 16.0];

  return (
    <div className="min-h-screen py-8">
      <div className="container mx-auto px-4">
        {/* Header */}
        <div className="flex items-center justify-between mb-8">
          <Link href="/">
            <Button variant="outline" className="bg-transparent border-[hsl(var(--casino-gold))]/30 text-[hsl(var(--casino-gold))] hover:bg-[hsl(var(--casino-gold))]/10">
              <ArrowLeft className="mr-2 h-4 w-4" />
              Back to Casino
            </Button>
          </Link>
          <h1 className="text-4xl font-display font-bold text-[hsl(var(--casino-gold))]">
            ⚪ Plinko
          </h1>
          <div className="text-right">
            <div className="text-sm text-gray-400">Your Balance</div>
            <div className="text-xl font-mono font-bold text-[hsl(var(--casino-gold))]">
              {user?.balance?.toLocaleString() || 0} Credits
            </div>
          </div>
        </div>

        {/* Plinko Board */}
        <Card className="felt-table p-8 mb-8 max-w-4xl mx-auto">
          <div className="text-center mb-8">
            <h3 className="text-2xl font-bold text-[hsl(var(--casino-gold))] mb-6">
              Drop the Ball
            </h3>

            {/* Plinko Board Visualization */}
            <div className="bg-gradient-to-b from-gray-800 to-gray-900 rounded-2xl p-8 mx-auto max-w-2xl border-4 border-[hsl(var(--casino-gold))]">
              {/* Drop Zone */}
              <div className="text-center mb-6">
                <motion.div
                  className="w-8 h-8 bg-white rounded-full mx-auto shadow-lg"
                  animate={dropMutation.isPending ? { y: [0, 300] } : {}}
                  transition={{ duration: 2, ease: "easeIn" }}
                >
                  <Circle className="w-8 h-8 text-red-500" fill="currentColor" />
                </motion.div>
              </div>

              {/* Pins Grid */}
              <div className="mb-6">
                {Array.from({ length: 8 }).map((_, row) => (
                  <div key={row} className="flex justify-center mb-4" style={{ paddingLeft: `${(row % 2) * 20}px` }}>
                    {Array.from({ length: 9 - Math.floor(row / 2) }).map((_, pin) => (
                      <div
                        key={pin}
                        className="w-3 h-3 bg-[hsl(var(--casino-gold))] rounded-full mx-2"
                      />
                    ))}
                  </div>
                ))}
              </div>

              {/* Buckets */}
              <div className="grid grid-cols-9 gap-1 mb-4">
                {multipliers.slice(0, 9).map((multiplier, index) => (
                  <div
                    key={index}
                    className={`text-center p-3 rounded-lg border-2 ${
                      ballPosition === index
                        ? 'bg-[hsl(var(--win-green))] border-[hsl(var(--win-green))] animate-pulse'
                        : multiplier >= 2.0
                        ? 'bg-red-600 border-red-500'
                        : multiplier >= 1.0
                        ? 'bg-yellow-600 border-yellow-500'
                        : 'bg-gray-600 border-gray-500'
                    }`}
                  >
                    <div className="text-white font-bold text-sm">{multiplier}x</div>
                  </div>
                ))}
              </div>

              {lastResult && (
                <div className="text-center">
                  <Badge className={`px-6 py-3 text-lg font-bold ${
                    lastResult.result === 'win' 
                      ? 'bg-[hsl(var(--win-green))] text-white' 
                      : 'bg-[hsl(var(--loss-red))] text-white'
                  }`}>
                    {lastResult.result === 'win' 
                      ? `${lastResult.multiplier}x - Won ${lastResult.payout} Credits!` 
                      : `${lastResult.multiplier}x - Lost ${betAmount} Credits`
                    }
                  </Badge>
                </div>
              )}
            </div>
          </div>

          {/* Bet Controls */}
          <div className="max-w-md mx-auto space-y-4">
            <h4 className="text-xl font-bold text-[hsl(var(--casino-gold))] text-center">Place Your Bet</h4>

            <FlexibleBetInput
              value={betAmount}
              onChange={setBetAmount}
              disabled={dropMutation.isPending}
              currency={balance?.currency || 'USD'}
              balance={parseFloat(balance?.balance || '0')}
              minBet={1}
              maxBet={1000}
              className="max-w-sm mx-auto"
            />

            <div className="text-center">
              <Button
                onClick={handleDrop}
                disabled={dropMutation.isPending || !user || user.balance < betAmount}
                className="casino-button px-12 py-4 text-xl font-bold"
              >
                ⚪ {dropMutation.isPending ? "Dropping..." : "Drop Ball"}
              </Button>
            </div>
          </div>
        </Card>

        {/* Multiplier Table */}
        <Card className="casino-card p-6">
          <h3 className="text-xl font-bold text-[hsl(var(--casino-gold))] mb-4">
            Multiplier Table
          </h3>
          <div className="grid grid-cols-3 md:grid-cols-6 gap-4">
            {multipliers.slice(0, 9).map((multiplier, index) => (
              <div
                key={index}
                className={`text-center p-3 rounded-lg ${
                  multiplier >= 2.0
                    ? 'bg-red-600/20 border border-red-500'
                    : multiplier >= 1.0
                    ? 'bg-yellow-600/20 border border-yellow-500'
                    : 'bg-gray-600/20 border border-gray-500'
                }`}
              >
                <div className="text-white font-bold">{multiplier}x</div>
                <div className="text-sm text-gray-400">Bucket {index + 1}</div>
              </div>
            ))}
          </div>

          <div className="mt-6 text-center text-gray-300">
            <p>Drop the ball and watch it bounce through the pins!</p>
            <p>Higher multipliers are rarer but give bigger payouts.</p>
          </div>
        </Card>
      </div>
    </div>
  );
}

client/src/pages/profile-page.tsx.content:
import { useState, useRef, useEffect } from "react";
import { MainLayout } from "@/components/layout/MainLayout";
import { 
  User, Mail, Phone, Shield, Calendar, Edit2, Save, AlertCircle, 
  Camera, Upload, X, Check, DollarSign, TrendingUp, Trophy, 
  Users, Gift, Gamepad2, Clock, MapPin, Star, Settings
} from "lucide-react";
import { useAuth } from "@/hooks/use-auth";
import { useToast } from "@/hooks/use-toast";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import { useCurrency } from "@/hooks/use-currency";
import { motion } from "framer-motion";

export default function ProfilePage() {
  const { user, refreshUser } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const fileInputRef = useRef<HTMLInputElement>(null);
  const { currencySymbol } = useCurrency();

  const [isEditing, setIsEditing] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [previewImage, setPreviewImage] = useState<string | null>(null);

  // Form state - Initialize with actual user data
  const [formData, setFormData] = useState({
    email: "",
    phone: "",
  });

  // Update form data when user data changes
  useEffect(() => {
    if (user) {
      setFormData(prev => ({
        ...prev,
        email: user.email || "",
        phone: user.phone || "",
      }));
    }
  }, [user]);

  // Fetch current profile picture with better caching
  const { data: profileData, refetch: refetchProfilePicture } = useQuery({
    queryKey: ['/api/profile/picture-url'],
    enabled: !!user,
    staleTime: 5 * 60 * 1000, // Cache for 5 minutes
    cacheTime: 10 * 60 * 1000, // Keep in cache for 10 minutes
    retry: 1,
    retryDelay: 1000
  });

  // Fetch user profile statistics
  const { data: profileStats, isLoading: statsLoading } = useQuery({
    queryKey: ['/api/user/profile-stats'],
    enabled: !!user,
    staleTime: 30000, // Cache for 30 seconds
  });

  // Profile picture upload mutation
  const uploadMutation = useMutation({
    mutationFn: async (file: File) => {
      const formData = new FormData();
      formData.append('profilePicture', file);

      const response = await fetch('/api/profile/upload-picture', {
        method: 'POST',
        body: formData,
        credentials: 'include'
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.message || 'Failed to upload profile picture');
      }

      return response.json();
    },
    onSuccess: () => {
      refetchProfilePicture();
      queryClient.invalidateQueries({ queryKey: ['/api/profile/picture-url'] });
      queryClient.invalidateQueries({ queryKey: ['/api/user'] });
      setPreviewImage(null);
      refreshUser();

      toast({
        title: "Profile Picture Updated",
        description: "Your profile picture has been updated successfully"
      });
    },
    onError: (error: Error) => {
      toast({
        title: "Upload Failed",
        description: error.message,
        variant: "destructive"
      });
    }
  });

  // Profile picture delete mutation
  const deleteMutation = useMutation({
    mutationFn: async () => {
      const response = await fetch('/api/profile/delete-picture', {
        method: 'DELETE',
        credentials: 'include'
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.message || 'Failed to delete profile picture');
      }

      return response.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['/api/profile/picture-url'] });
      queryClient.invalidateQueries({ queryKey: ['/api/user'] });
      refreshUser();
      toast({
        title: "Profile Picture Removed",
        description: "Your profile picture has been removed"
      });
    },
    onError: (error: Error) => {
      toast({
        title: "Delete Failed",
        description: error.message,
        variant: "destructive"
      });
    }
  });

  // File upload handlers
  const validateFile = (file: File): string | null => {
    const allowedTypes = ['image/jpeg', 'image/jpg', 'image/png', 'image/webp'];
    const maxSize = 5 * 1024 * 1024; // 5MB

    if (!allowedTypes.includes(file.type)) {
      return 'Please select a valid image file (JPEG, PNG, or WebP)';
    }

    if (file.size > maxSize) {
      return 'File size must be less than 5MB';
    }

    return null;
  };

  const handleFileSelect = (file: File) => {
    const error = validateFile(file);
    if (error) {
      toast({
        title: "Invalid File",
        description: error,
        variant: "destructive"
      });
      return;
    }

    // Create preview
    const reader = new FileReader();
    reader.onload = (e) => {
      setPreviewImage(e.target?.result as string);
    };
    reader.readAsDataURL(file);

    // Upload file
    uploadMutation.mutate(file);
  };

  const handleFileInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      handleFileSelect(file);
    }
    // Reset input
    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);

    const files = e.dataTransfer.files;
    if (files.length > 0) {
      handleFileSelect(files[0]);
    }
  };

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError(null);
    setSuccess(null);

    // Basic email validation
    if (formData.email && !/\S+@\S+\.\S+/.test(formData.email)) {
      setError("Please enter a valid email address");
      setIsSubmitting(false);
      return;
    }

    try {
      const response = await fetch('/api/user/profile', {
        method: 'PATCH',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          email: formData.email,
          phone: formData.phone,
        }),
        credentials: 'include'
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.message || "Failed to update profile");
      }

      setSuccess("Profile updated successfully");
      setIsEditing(false);
      setFormData(prev => ({
        ...prev,
        email: user?.email || "",
        phone: user?.phone || "",
      }));

      // Refresh user data
      refreshUser();
      queryClient.invalidateQueries({ queryKey: ['/api/user/profile-stats'] });

      toast({
        title: "Profile Updated",
        description: "Your profile has been updated successfully",
      });
    } catch (err) {
      setError(err instanceof Error ? err.message : "An error occurred");

      toast({
        title: "Update Failed",
        description: err instanceof Error ? err.message : "Failed to update profile",
        variant: "destructive",
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  const formatDate = (dateString?: string | Date) => {
    if (!dateString) return "N/A";
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'long',
      day: 'numeric'
    });
  };

  const formatCurrency = (amount: string | number) => {
    const num = typeof amount === 'string' ? parseFloat(amount) : amount;
    return `${currencySymbol}${num.toLocaleString(undefined, { 
      minimumFractionDigits: 2, 
      maximumFractionDigits: 2 
    })}`;
  };

  return (
    <MainLayout>
      <div className="min-h-screen bg-gradient-to-br from-background via-background to-muted/20 p-6">
