                      <p className="text-sm font-medium text-foreground">Secure Logout</p>
                      <p className="text-xs text-muted-foreground mt-1">Always log out when using shared or public computers</p>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </motion.div>
          </div>
        </div>
      </div>
    </MainLayout>
  );
}

