import { useState } from "react";
import { Link } from "wouter";

// Self-contained demo page that doesn't depend on auth or websockets
export default function StandaloneDemo() {
  const [betAmount, setBetAmount] = useState<number>(10);
  const [isSpinning, setIsSpinning] = useState<boolean>(false);
  const [gameResult, setGameResult] = useState<any>(null);
  const [balance, setBalance] = useState<number>(1000);

  // Format money values
  const formatMoney = (amount: number) => {
    return new Intl.NumberFormat('en-US', {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2
    }).format(amount);
  };

  // Get currency symbol
  const getCurrencySymbol = (currency: string = 'USD') => {
    switch(currency) {
      case 'USD': return '$';
      case 'BDT': return '৳';
      case 'INR': return '₹';
      case 'BTC': return '₿';
      default: return '$';
    }
  };

  // Handle spin button click
  const handleSpin = async () => {
    if (balance < betAmount) {
      alert("Insufficient balance!");
      return;
    }

    setIsSpinning(true);
    setBalance(prev => prev - betAmount);

    // Simulate network delay
    setTimeout(() => {
      // Randomly determine if this is a win (50/50 chance)
      const isWin = Math.random() > 0.5;

      // Create mock game result
      const mockResult = {
        isWin: isWin,
        winAmount: isWin ? betAmount * 2 : 0,
        multiplier: isWin ? 2 : 0,
        gameData: {
          reels: ['🍒', '7️⃣', '🍋', '💎', '🍊'] // Default symbols
        }
      };

      // Set a more interesting pattern for wins
      if (isWin) {
        mockResult.gameData.reels = ['🍇', '7️⃣', '7️⃣', '7️⃣', '🍒'];
        setBalance(prev => prev + mockResult.winAmount);
      }

      setGameResult(mockResult);
      setIsSpinning(false);
    }, 1000);
  };

  return (
    <div className="min-h-screen bg-[#0f0f1a] text-white">
      {/* Header */}
      <header className="h-16 bg-[#07070e] border-b border-[#1f1f3a] flex items-center justify-between px-6">
        <div className="flex items-center">
          <h1 className="text-2xl font-bold mr-6">
            Shadow <span className="text-[#7c3aed]">Casino</span>
          </h1>

          {/* Nav menu */}
          <div className="hidden md:flex items-center space-x-4">
            <Link href="/slots" className="text-white hover:text-[#7c3aed] transition-colors">
              Slots
            </Link>
            <Link href="/dice" className="text-white hover:text-[#7c3aed] transition-colors">
              Dice
            </Link>
            <Link href="/plinko" className="text-white hover:text-[#7c3aed] transition-colors">
              Plinko
            </Link>
            <Link href="/auth" className="text-white hover:text-[#7c3aed] transition-colors">
              Login
            </Link>
          </div>
        </div>

        <div className="px-4 py-2 bg-[#1a1a2e] rounded-md border border-[#2d2d4a]">
          <span className="text-gray-400 mr-2">Balance:</span>
          <span className="font-bold text-white">
            ${formatMoney(balance)}
          </span>
          <span className="text-xs text-gray-400 ml-1">USD</span>
        </div>
      </header>

      <div className="p-6">
        <h1 className="text-2xl font-bold mb-6">Slots Game - Demo</h1>

        <div className="bg-[#1a1a2e] rounded-lg p-8">
          <div className="max-w-2xl mx-auto">
            {/* Display reels */}
            <div className="bg-[#07070e] rounded-lg p-6 mb-6">
              <div className="relative">
                {/* Win line display */}
                {gameResult?.isWin && (
                  <div className="absolute left-0 right-0 top-1/2 transform -translate-y-1/2 h-1 bg-green-500 animate-pulse z-10"></div>
                )}

                <div className="grid grid-cols-5 gap-3 relative">
                  {gameResult?.gameData?.reels ? (
                    gameResult.gameData.reels.map((symbol: string, index: number) => (
                      <div 
                        key={index} 
                        className={`h-24 flex items-center justify-center text-4xl bg-[#1a1a2e] rounded-md border-2 overflow-hidden
                          ${gameResult.isWin && index > 0 && index < 4 
                            ? 'border-green-500 animate-pulse' 
                            : 'border-[#2d2d4a]'
                          }`}
                      >
                        <div className={isSpinning ? 'animate-spin' : ''}>
                          {symbol}
                        </div>

                        {/* Highlight effect for winning symbols */}
                        {gameResult.isWin && index > 0 && index < 4 && (
                          <div className="absolute inset-0 bg-green-500/10 rounded-md"></div>
                        )}
                      </div>
                    ))
                  ) : (
                    Array(5).fill(0).map((_, index) => (
                      <div 
                        key={index}
                        className="h-24 flex items-center justify-center text-4xl bg-[#1a1a2e] rounded-md border-2 border-[#2d2d4a]"
                      >
                        {isSpinning ? (
                          <div className="animate-spin">🎰</div>
                        ) : (
                          "?"
                        )}
                      </div>
                    ))
                  )}
                </div>
              </div>
            </div>

            {/* Game controls */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {/* Bet controls */}
              <div className="bg-[#1a1a2e] rounded-lg p-4">
                <h3 className="text-lg font-medium mb-2">Your Bet</h3>
                <div className="flex items-center mb-4">
                  <button 
                    className="bg-[#07070e] rounded-l-md px-3 py-2 border border-[#2d2d4a]"
                    onClick={() => setBetAmount(Math.max(1, betAmount - 10))}
                    disabled={isSpinning}
                  >
                    -
                  </button>
                  <div className="px-4 py-2 border-t border-b border-[#2d2d4a]">
                    ${formatMoney(betAmount)}
                  </div>
                  <button 
                    className="bg-[#07070e] rounded-r-md px-3 py-2 border border-[#2d2d4a]"
                    onClick={() => setBetAmount(betAmount + 10)}
                    disabled={isSpinning}
                  >
                    +
                  </button>
                </div>
                <div className="grid grid-cols-3 gap-2">
                  <button 
                    className="bg-[#07070e] rounded px-2 py-1 border border-[#2d2d4a] text-sm"
                    onClick={() => setBetAmount(10)}
                    disabled={isSpinning}
                  >
                    10
                  </button>
                  <button 
                    className="bg-[#07070e] rounded px-2 py-1 border border-[#2d2d4a] text-sm"
                    onClick={() => setBetAmount(50)}
                    disabled={isSpinning}
                  >
                    50
                  </button>
                  <button 
                    className="bg-[#07070e] rounded px-2 py-1 border border-[#2d2d4a] text-sm"
                    onClick={() => setBetAmount(100)}
                    disabled={isSpinning}
                  >
                    100
                  </button>
                </div>
              </div>

              {/* Spin button */}
              <div className="bg-[#1a1a2e] rounded-lg p-4 flex flex-col items-center justify-center">
                <button 
                  className={`w-full h-full bg-[#7c3aed] rounded-lg flex flex-col items-center justify-center text-white font-bold ${
                    isSpinning ? 'opacity-70 cursor-not-allowed' : 'hover:bg-[#6d28d9]'
                  }`}
                  onClick={handleSpin}
                  disabled={isSpinning}
                >
                  {isSpinning ? (
                    <>
                      <div className="animate-spin h-8 w-8 border-4 border-white border-t-transparent rounded-full mb-2"></div>
                      <span>Spinning...</span>
                    </>
                  ) : (
                    <>
                      <span className="text-2xl mb-1">🎰</span>
                      <span>SPIN</span>
                    </>
                  )}
                </button>
              </div>

              {/* Result display */}
              <div className="bg-[#1a1a2e] rounded-lg p-4">
                <h3 className="text-lg font-medium mb-2">Result</h3>
                {gameResult ? (
                  <div className={`p-3 rounded-md ${gameResult.isWin ? 'bg-green-500/20' : 'bg-red-500/20'}`}>
                    <div className="text-center font-bold text-xl mb-1">
                      {gameResult.isWin ? 'YOU WON!' : 'YOU LOST'}
                    </div>
                    {gameResult.isWin && (
                      <div className="text-center">
                        <span className="text-green-400 font-medium">
                          ${formatMoney(gameResult.winAmount)}
                        </span>
                      </div>
                    )}
                  </div>
                ) : (
                  <div className="text-gray-400 text-center p-2">
                    Place your bet and hit SPIN!
                  </div>
                )}
              </div>
            </div>

            {/* Game rules */}
            <div className="mt-6 p-4 bg-[#07070e] rounded-lg">
              <h3 className="font-medium mb-2">How to Play:</h3>
              <ul className="list-disc list-inside text-sm text-gray-400">
                <li>Set your bet amount using the controls</li>
                <li>Hit the SPIN button to play</li>
                <li>Match 3 symbols in the middle to win</li>
                <li>Different symbols have different payouts</li>
              </ul>
            </div>

            <div className="mt-6 p-4 bg-yellow-500/10 border border-yellow-500/30 rounded-lg">
              <h3 className="text-yellow-500 font-medium mb-2">Demo Mode</h3>
              <p className="text-sm text-gray-300">
                This is a standalone demo version of the Slots game with no backend connectivity.
                Changes to your balance are simulated and not persistent.
              </p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

client/src/pages/themes.tsx.content:
import { useState } from "react";
import { MainLayout } from "@/components/layout/MainLayout";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { useToast } from "@/hooks/use-toast";
import { Palette, Star, Crown, Zap, Heart, Sparkles, Gamepad2 } from "lucide-react";
import { motion } from "framer-motion";
import { allThemes, getThemeById } from "@/lib/themes";
import { useTheme } from "@/hooks/use-theme";

export default function ThemesPage() {
  const { currentTheme, setTheme } = useTheme();
  const { toast } = useToast();
  const [selectedCategory, setSelectedCategory] = useState<string>("all");

  const handleThemeChange = (themeId: string) => {
    // Add smooth transition visual feedback
    const themeCard = document.querySelector(`[data-theme-id="${themeId}"]`);
    if (themeCard) {
      themeCard.classList.add('theme-applying');
    }

    setTheme(themeId);

    // Show success message after transition completes
    setTimeout(() => {
      toast({
        title: "Theme Applied",
        description: `Successfully switched to ${getThemeById(themeId).name}`,
        variant: "default",
      });

      // Remove applying state
      if (themeCard) {
        themeCard.classList.remove('theme-applying');
      }
    }, 800);
  };

  const getIconForCategory = (category: string) => {
    switch (category) {
      case 'dark': return Palette;
      case 'vibrant': return Zap;
      case 'elegant': return Crown;
      case 'neon': return Sparkles;
      case 'nature': return Heart;
      default: return Palette;
    }
  };

  const filteredThemes = selectedCategory === "all" 
    ? allThemes 
    : allThemes.filter(theme => theme.category === selectedCategory);

  const categories = [
    { id: "all", name: "All Themes" },
    { id: "dark", name: "Dark" },
    { id: "vibrant", name: "Vibrant" },
    { id: "elegant", name: "Elegant" },
    { id: "neon", name: "Neon" },
    { id: "nature", name: "Nature" }
  ];

  return (
    <MainLayout>
      <div className="container mx-auto px-4 py-8">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
        >
          <div className="mb-8">
            <h1 className="text-3xl lg:text-4xl font-bold font-heading mb-4">
              <Palette className="inline mr-3" />
              Themes & Customization
            </h1>
            <p className="text-gray-400 text-lg">
              Personalize your gaming experience with our collection of themes
            </p>
          </div>

          {/* Category Filter */}
          <div className="mb-8">
            <div className="flex flex-wrap gap-2">
              {categories.map((category) => (
                <Button
                  key={category.id}
                  variant={selectedCategory === category.id ? "default" : "outline"}
                  size="sm"
                  onClick={() => setSelectedCategory(category.id)}
                  className="mb-2 category-filter transform transition-all duration-300 hover:scale-105"
                >
                  {category.name}
                </Button>
              ))}
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredThemes.map((theme, index) => {
              const IconComponent = getIconForCategory(theme.category);
              const isCurrentTheme = currentTheme.id === theme.id;

              return (
                <motion.div
                  key={theme.id}
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ duration: 0.5, delay: index * 0.1 }}
                  data-theme-id={theme.id}
                >
                  <Card className={`theme-preview glow-effect relative overflow-hidden transition-all duration-500 hover:scale-105 hover:shadow-xl ${
                    isCurrentTheme ? 'ring-2 ring-blue-500 shadow-lg shadow-blue-500/20' : ''
                  }`}>
                    <CardHeader className="pb-4">
                      <div className="flex items-center justify-between">
                        <div className="flex items-center space-x-2">
                          <IconComponent className="w-5 h-5" />
                          <CardTitle className="text-lg">{theme.name}</CardTitle>
                        </div>
                        <div className="flex space-x-2">
                          {isCurrentTheme && (
                            <Badge variant="default" className="bg-green-500/20 text-green-400 border-green-500/30">
                              Current
                            </Badge>
                          )}
                          {theme.popularity >= 4 && (
                            <Badge variant="outline" className="border-yellow-500/50 text-yellow-400">
                              <Star className="w-3 h-3 mr-1" />
                              Popular
                            </Badge>
                          )}
                        </div>
                      </div>
                      <p className="text-sm text-gray-400">{theme.description}</p>
                      <div className="flex items-center space-x-4 text-xs text-gray-500">
                        <span className="capitalize">{theme.category}</span>
                        <span className="capitalize">{theme.mood}</span>
                        <div className="flex items-center">
                          <Star className="w-3 h-3 mr-1 text-yellow-400" />
                          <span>{theme.popularity}/5</span>
                        </div>
                      </div>
                    </CardHeader>

                    <CardContent className="space-y-4">
                      {/* Theme Preview */}
                      <div 
                        className="w-full h-20 rounded-lg relative overflow-hidden gradient-animated"
                        style={{ background: theme.gradients.background }}
                      >
                        <div className="absolute inset-0" style={{ background: theme.gradients.card, opacity: 0.6 }}></div>
                        <div className="absolute inset-0 bg-gradient-to-br from-transparent via-white/5 to-transparent"></div>
                        <div className="absolute bottom-2 left-2 right-2 flex space-x-1">
                          {Object.values(theme.colors).slice(0, 6).map((color, i) => (
                            <div
                              key={i}
                              className="w-4 h-4 rounded-full border border-white/20 shadow-sm transition-transform hover:scale-110"
                              style={{ backgroundColor: color }}
                            />
                          ))}
                        </div>
                      </div>

                      {/* Key Colors */}
                      <div className="space-y-2">
                        <h4 className="text-sm font-medium text-gray-300">Key Colors</h4>
                        <div className="grid grid-cols-3 gap-2">
                          <div className="text-center">
                            <div
                              className="w-full h-8 rounded border border-gray-600"
                              style={{ backgroundColor: theme.colors.primary }}
                            />
                            <span className="text-xs text-gray-400 mt-1 block">Primary</span>
                          </div>
                          <div className="text-center">
                            <div
                              className="w-full h-8 rounded border border-gray-600"
                              style={{ backgroundColor: theme.colors.accent }}
                            />
                            <span className="text-xs text-gray-400 mt-1 block">Accent</span>
                          </div>
                          <div className="text-center">
                            <div
                              className="w-full h-8 rounded border border-gray-600"
                              style={{ backgroundColor: theme.colors.background }}
                            />
                            <span className="text-xs text-gray-400 mt-1 block">Background</span>
                          </div>
                        </div>
                      </div>

                      {/* Apply Button */}
                      <Button
                        onClick={() => handleThemeChange(theme.id)}
                        className="w-full glow-effect transition-all duration-300"
                        variant={isCurrentTheme ? "default" : "outline"}
                        disabled={isCurrentTheme}
                        style={!isCurrentTheme ? { 
                          background: theme.gradients.primary,
                          borderColor: theme.colors.primary,
                          color: 'white'
                        } : undefined}
                      >
                        {isCurrentTheme ? "Currently Active" : "Apply Theme"}
                      </Button>
                    </CardContent>
                  </Card>
                </motion.div>
              );
            })}
          </div>



          {/* Theme Features */}
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5, delay: 1.0 }}
            className="mt-12 grid grid-cols-1 md:grid-cols-3 gap-6"
          >
            <Card>
              <CardContent className="p-6 text-center">
                <Palette className="w-8 h-8 text-blue-400 mx-auto mb-4" />
                <h4 className="font-semibold mb-2">Custom Colors</h4>
                <p className="text-sm text-gray-400">
                  Personalize every element with your favorite colors
                </p>
              </CardContent>
            </Card>

            <Card>
              <CardContent className="p-6 text-center">
                <Gamepad2 className="w-8 h-8 text-green-400 mx-auto mb-4" />
                <h4 className="font-semibold mb-2">Gaming Optimized</h4>
                <p className="text-sm text-gray-400">
                  Themes designed for optimal gaming performance
                </p>
              </CardContent>
            </Card>

            <Card>
              <CardContent className="p-6 text-center">
                <Zap className="w-8 h-8 text-purple-400 mx-auto mb-4" />
                <h4 className="font-semibold mb-2">Instant Preview</h4>
                <p className="text-sm text-gray-400">
                  See changes instantly without page reloads
                </p>
              </CardContent>
            </Card>
          </motion.div>
        </motion.div>
      </div>
    </MainLayout>
  );
}

client/src/pages/transaction-history-pag.content:
import { useState, useEffect } from "react";
import { MainLayout } from "@/components/layout/MainLayout";
import { ClipboardList, Calendar, ArrowUpRight, ArrowDownLeft, RefreshCw, AlertCircle, Search } from "lucide-react";
import { useToast } from "@/hooks/use-toast";

// Define TransactionType enum
enum TransactionType {
  DEPOSIT = "deposit",
  WITHDRAWAL = "withdrawal",
  BET = "bet",
  WIN = "win"
}

interface Transaction {
  id: number;
  userId: number;
  amount: string;
  currency: string;
  type: TransactionType;
  status: string;
  createdAt: string;
  metadata?: any;
}

export default function TransactionHistoryPage() {
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState("");
  const [typeFilter, setTypeFilter] = useState<string | null>(null);
  const { toast } = useToast();

  useEffect(() => {
    fetchTransactions();
  }, []);

  const fetchTransactions = async () => {
    setIsLoading(true);
    setError(null);

    try {
      const response = await fetch('/api/wallet/transactions');
      if (!response.ok) {
        throw new Error('Failed to fetch transaction history');
      }

      const data = await response.json();
      setTransactions(data);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'An error occurred');
      toast({
        title: "Error",
        description: err instanceof Error ? err.message : 'Failed to load transactions',
        variant: "destructive",
      });
    } finally {
      setIsLoading(false);
    }
  };

  const getTransactionTypeIcon = (type: string) => {
    switch (type) {
      case "deposit":
        return <ArrowDownLeft className="h-4 w-4 text-green-500" />;
      case "withdrawal":
        return <ArrowUpRight className="h-4 w-4 text-amber-500" />;
      case "bet":
        return <span className="text-xs font-semibold p-1 bg-red-500/20 text-red-400 rounded">BET</span>;
      case "win":
        return <span className="text-xs font-semibold p-1 bg-green-500/20 text-green-400 rounded">WIN</span>;
      default:
        return null;
    }
  };

  const getTransactionStatusBadge = (status: string) => {
    switch (status) {
      case "completed":
        return <span className="text-xs px-2 py-0.5 bg-green-500/20 text-green-500 rounded-full">Completed</span>;
      case "pending":
        return <span className="text-xs px-2 py-0.5 bg-yellow-500/20 text-yellow-500 rounded-full">Pending</span>;
      case "failed":
        return <span className="text-xs px-2 py-0.5 bg-red-500/20 text-red-500 rounded-full">Failed</span>;
      default:
        return <span className="text-xs px-2 py-0.5 bg-gray-500/20 text-gray-400 rounded-full">{status}</span>;
    }
  };

  const formatDate = (dateString: string) => {
    const date = new Date(dateString);
    return new Intl.DateTimeFormat('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    }).format(date);
  };

  const formatTime = (dateString: string) => {
    const date = new Date(dateString);
    return new Intl.DateTimeFormat('en-US', {
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
    }).format(date);
  };

  const getGameDetails = (transaction: Transaction) => {
    // If no metadata, return empty
    if (!transaction.metadata || !transaction.metadata.gameType) {
      return <span className="text-gray-500">-</span>;
    }

    const metadata = transaction.metadata;
    const gameType = metadata.gameType;

    // Get game icon based on type
    const getGameIcon = (type: string) => {
      switch (type.toUpperCase()) {
        case 'SLOTS':
          return '🎰';
        case 'DICE':
          return '🎲';
        case 'PLINKO':
        case 'PLINKO_MASTER':
          return '📍';
        default:
          return '🎮';
      }
    };

    return (
      <div className="flex flex-col">
        <div className="flex items-center">
          <span className="text-lg mr-1">{getGameIcon(gameType)}</span>
          <span className="text-sm font-medium capitalize">{gameType.replace('_', ' ')}</span>
        </div>
        {transaction.type === 'win' && metadata.multiplier && (
          <span className="text-xs text-green-500">
            Multiplier: {metadata.multiplier}x
          </span>
        )}
        {transaction.type === 'bet' && metadata.betAmount && (
          <span className="text-xs text-gray-500">
            Bet: {metadata.betAmount}
          </span>
        )}
      </div>
    );
  };

  const getAmountDisplay = (amount: string, type: string, currency: string) => {
    const amountNum = parseFloat(amount);

    const getCurrencySymbol = (currencyCode: string) => {
      switch (currencyCode) {
        case 'USD': return '$';
        case 'BDT': return '৳';
        case 'INR': return '₹';
        case 'BTC': return '₿';
        default: return '';
      }
    };

    const formattedAmount = amountNum.toLocaleString(undefined, {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2
    });

    if (type === "withdrawal" || type === "bet") {
      return <span className="text-red-500">-{getCurrencySymbol(currency)}{formattedAmount}</span>;
    } else {
      return <span className="text-green-500">+{getCurrencySymbol(currency)}{formattedAmount}</span>;
    }
  };

  const filteredTransactions = transactions.filter(transaction => {
    // Apply type filter
    if (typeFilter && transaction.type !== typeFilter) {
      return false;
    }

    // Apply search term filter (search by amount, currency, type, and status)
    if (searchTerm) {
      const searchLower = searchTerm.toLowerCase();
      return (
        transaction.amount.includes(searchTerm) ||
        transaction.currency.toLowerCase().includes(searchLower) ||
        transaction.type.toLowerCase().includes(searchLower) ||
        transaction.status.toLowerCase().includes(searchLower)
      );
    }

    return true;
  });

  // Get transaction statistics
  const getTotalDeposits = () => {
    return transactions
      .filter(t => t.type === "deposit" && t.status === "completed")
      .reduce((sum, t) => sum + parseFloat(t.amount), 0);
  };

  const getTotalWithdrawals = () => {
    return transactions
      .filter(t => t.type === "withdrawal" && t.status === "completed")
      .reduce((sum, t) => sum + parseFloat(t.amount), 0);
  };

  return (
    <MainLayout>
      <div className="p-6 max-w-6xl mx-auto">
        <div className="flex items-center mb-6">
          <ClipboardList className="h-8 w-8 text-primary mr-3" />
          <h1 className="text-3xl font-bold">Transaction History</h1>
        </div>

        {/* Stats Cards */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
          <div className="bg-card rounded-lg p-4 shadow-md animate-fadeIn">
            <div className="flex items-center justify-between mb-2">
              <h3 className="text-sm text-gray-400">Total Transactions</h3>
              <Calendar className="h-4 w-4 text-gray-400" />
            </div>
            <p className="text-2xl font-bold">{transactions.length}</p>
          </div>

          <div className="bg-card rounded-lg p-4 shadow-md animate-fadeIn">
            <div className="flex items-center justify-between mb-2">
              <h3 className="text-sm text-gray-400">Total Deposits</h3>
              <ArrowDownLeft className="h-4 w-4 text-green-500" />
            </div>
            <p className="text-2xl font-bold text-green-500">
              +${getTotalDeposits().toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
            </p>
          </div>

          <div className="bg-card rounded-lg p-4 shadow-md animate-fadeIn">
            <div className="flex items-center justify-between mb-2">
              <h3 className="text-sm text-gray-400">Total Withdrawals</h3>
              <ArrowUpRight className="h-4 w-4 text-amber-500" />
            </div>
            <p className="text-2xl font-bold text-amber-500">
              -${getTotalWithdrawals().toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
            </p>
          </div>

          <div className="bg-card rounded-lg p-4 shadow-md animate-fadeIn">
            <div className="flex items-center justify-between mb-2">
              <h3 className="text-sm text-gray-400">Net Balance</h3>
              <span className="text-xs px-2 py-0.5 bg-primary/20 text-primary rounded-full">Balance</span>
            </div>
            <p className="text-2xl font-bold text-primary">
              ${(getTotalDeposits() - getTotalWithdrawals()).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
            </p>
          </div>
        </div>

        {/* Filter and Search */}
        <div className="bg-card rounded-lg shadow-lg p-4 mb-6 animate-fadeIn">
          <div className="flex flex-col md:flex-row gap-4">
            <div className="flex-1">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
                <input
                  type="text"
                  placeholder="Search transactions..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  className="pl-9 pr-4 py-2 w-full bg-background border border-border rounded-md focus:outline-none focus:ring-1 focus:ring-primary"
                />
              </div>
            </div>

            <div className="flex space-x-2">
              <button
                onClick={() => setTypeFilter(null)}
                className={`px-3 py-1.5 rounded-md text-sm ${
                  typeFilter === null
                    ? 'bg-primary text-white'
                    : 'bg-background hover:bg-background-light'
                }`}
              >
                All
              </button>
              <button
                onClick={() => setTypeFilter("deposit")}
                className={`px-3 py-1.5 rounded-md text-sm flex items-center ${
                  typeFilter === "deposit"
                    ? 'bg-green-500/20 text-green-500'
                    : 'bg-background hover:bg-background-light'
                }`}
              >
                <ArrowDownLeft className="h-4 w-4 mr-1" />
                Deposits
              </button>
              <button
                onClick={() => setTypeFilter("withdrawal")}
                className={`px-3 py-1.5 rounded-md text-sm flex items-center ${
                  typeFilter === "withdrawal"
                    ? 'bg-amber-500/20 text-amber-500'
                    : 'bg-background hover:bg-background-light'
                }`}
              >
                <ArrowUpRight className="h-4 w-4 mr-1" />
                Withdrawals
              </button>
              <button
                onClick={() => setTypeFilter("bet")}
                className={`px-3 py-1.5 rounded-md text-sm flex items-center ${
                  typeFilter === "bet"
                    ? 'bg-red-500/20 text-red-500'
                    : 'bg-background hover:bg-background-light'
                }`}
              >
                <span className="mr-1">🎲</span>
                Bets
              </button>
              <button
                onClick={() => setTypeFilter("win")}
                className={`px-3 py-1.5 rounded-md text-sm flex items-center ${
                  typeFilter === "win"
                    ? 'bg-green-500/20 text-green-500'
                    : 'bg-background hover:bg-background-light'
                }`}
              >
                <span className="mr-1">🏆</span>
                Wins
              </button>
            </div>

            <button
              onClick={fetchTransactions}
              disabled={isLoading}
