import React, { useState, useEffect } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { apiRequest } from '@/lib/queryClient';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { useToast } from '@/hooks/use-toast';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import { 
  Plus, 
  Loader2, 
  Edit, 
  Trash, 
  ExternalLink,
  Clock,
  ToggleLeft,
  ToggleRight,
  Search,
  Globe
} from 'lucide-react';
import { Switch } from '@/components/ui/switch';

interface RedirectLink {
  id: number;
  url: string;
  intervalMinutes: number;
  isActive: boolean;
  createdAt: string;
  updatedAt: string;
  createdBy: string;
}

export function AdvertisementManagement() {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [searchQuery, setSearchQuery] = useState("");
  const [isAddDialogOpen, setIsAddDialogOpen] = useState(false);
  const [isEditDialogOpen, setIsEditDialogOpen] = useState(false);
  const [editingLink, setEditingLink] = useState<RedirectLink | null>(null);
  const [formData, setFormData] = useState({
    url: "",
    intervalMinutes: 5,
    isActive: true
  });

  // Fetch redirect links
  const { data: links, isLoading, error } = useQuery<RedirectLink[]>({
    queryKey: ["/api/admin/redirect-links"],
  });

  // Create redirect link mutation
  const createLinkMutation = useMutation({
    mutationFn: async (data: { url: string; intervalMinutes: number; isActive: boolean }) => {
      const res = await apiRequest("POST", "/api/admin/redirect-links", data);
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/redirect-links"] });
      setIsAddDialogOpen(false);
      resetForm();
      toast({
        title: "Success",
        description: "Advertisement link created successfully",
      });
    },
    onError: (error: Error) => {
      toast({
        title: "Error",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  // Update redirect link mutation
  const updateLinkMutation = useMutation({
    mutationFn: async ({ id, data }: { id: number; data: Partial<{ url: string; intervalMinutes: number; isActive: boolean }> }) => {
      const res = await apiRequest("PUT", `/api/admin/redirect-links/${id}`, data);
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/redirect-links"] });
      setIsEditDialogOpen(false);
      resetForm();
      toast({
        title: "Success",
        description: "Advertisement link updated successfully",
      });
    },
    onError: (error: Error) => {
      toast({
        title: "Error",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  // Delete redirect link mutation
  const deleteLinkMutation = useMutation({
    mutationFn: async (id: number) => {
      const res = await apiRequest("DELETE", `/api/admin/redirect-links/${id}`);
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/redirect-links"] });
      toast({
        title: "Success",
        description: "Advertisement link deleted successfully",
      });
    },
    onError: (error: Error) => {
      toast({
        title: "Error",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const resetForm = () => {
    setFormData({
      url: "",
      intervalMinutes: 5,
      isActive: true
    });
    setEditingLink(null);
  };

  const handleCreateLink = () => {
    if (!formData.url.trim()) {
      toast({
        title: "Error",
        description: "URL is required",
        variant: "destructive",
      });
      return;
    }

    if (!formData.url.startsWith('http://') && !formData.url.startsWith('https://')) {
      toast({
        title: "Error",
        description: "URL must start with http:// or https://",
        variant: "destructive",
      });
      return;
    }

    createLinkMutation.mutate(formData);
  };

  const handleEditLink = (link: RedirectLink) => {
    setEditingLink(link);
    setFormData({
      url: link.url,
      intervalMinutes: link.intervalMinutes,
      isActive: link.isActive
    });
    setIsEditDialogOpen(true);
  };

  const handleUpdateLink = () => {
    if (!editingLink) return;

    if (!formData.url.trim()) {
      toast({
        title: "Error",
        description: "URL is required",
        variant: "destructive",
      });
      return;
    }

    if (!formData.url.startsWith('http://') && !formData.url.startsWith('https://')) {
      toast({
        title: "Error",
        description: "URL must start with http:// or https://",
        variant: "destructive",
      });
      return;
    }

    updateLinkMutation.mutate({
      id: editingLink.id,
      data: formData
    });
  };

  const handleToggleActive = (link: RedirectLink) => {
    updateLinkMutation.mutate({
      id: link.id,
      data: { isActive: !link.isActive }
    });
  };

  const handleDeleteLink = (id: number) => {
    if (confirm("Are you sure you want to delete this advertisement link?")) {
      deleteLinkMutation.mutate(id);
    }
  };

  const filteredLinks = links?.filter(link =>
    link.url && link.url.toLowerCase().includes(searchQuery.toLowerCase())
  ) || [];

  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-64">
        <Loader2 className="w-8 h-8 animate-spin text-primary" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-50 dark:bg-red-900/20 p-4 rounded-lg">
        <p className="text-red-800 dark:text-red-300">
          Error loading redirect links: {error instanceof Error ? error.message : 'Unknown error'}
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-6 w-full max-w-full">
      {/* Header */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 w-full">
        <div className="flex-1 min-w-0">
          <h3 className="text-lg font-semibold">Advertisement Management</h3>
          <p className="text-sm text-gray-500">Manage automatic advertisement redirect links for users</p>
        </div>
        <div className="flex-shrink-0 w-full sm:w-auto">
          <Button onClick={() => setIsAddDialogOpen(true)} className="w-full sm:w-auto whitespace-nowrap">
            <Plus className="h-4 w-4 mr-2" />
            Add Advertisement Link
          </Button>
        </div>
      </div>

      {/* Search */}
      <div className="relative">
        <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-gray-400" />
        <Input
          placeholder="Search by URL..."
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
          className="pl-10"
        />
      </div>

      {/* Table */}
      <div className="border rounded-lg overflow-hidden w-full">
        <div className="overflow-x-auto">
          <Table className="w-full table-fixed">
            <TableHeader>
              <TableRow>
                <TableHead className="w-2/5 min-w-[200px]">URL</TableHead>
                <TableHead className="w-1/6 min-w-[100px]">Interval</TableHead>
                <TableHead className="w-1/6 min-w-[100px]">Status</TableHead>
                <TableHead className="w-1/6 min-w-[100px]">Created</TableHead>
                <TableHead className="w-1/6 min-w-[120px] text-right">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {filteredLinks.length === 0 ? (
                <TableRow>
                  <TableCell colSpan={5} className="text-center py-8 text-gray-500">
                    No advertisement links found
                  </TableCell>
                </TableRow>
              ) : (
                filteredLinks.map((link) => (
                  <TableRow key={link.id}>
                    <TableCell className="max-w-0">
                      <div className="flex items-center gap-2 min-w-0">
                        <Globe className="h-4 w-4 text-gray-400 flex-shrink-0" />
                        <span className="font-mono text-sm truncate flex-1 min-w-0" title={link.url}>
                          {link.url}
                        </span>
                        <a
