import { useState } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { apiRequest, queryClient } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { Loader2 } from "lucide-react";
import { GameType } from "@shared/schema";
import { Button } from "@/components/ui/button";
import { Slider } from "@/components/ui/slider";
import { Input } from "@/components/ui/input";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";

interface GameSettings {
  id: number;
  gameType: GameType;
  winChance: number;
  maxMultiplier: number;
  lastUpdated: string;
  updatedBy: number | null;
}

interface AllGameSettings {
  slots: GameSettings;
  dice: GameSettings;
  plinko: GameSettings;
}

export function GameControls() {
  const { toast } = useToast();
  const [riggedMode, setRiggedMode] = useState(true);
  const [maxWinLimit, setMaxWinLimit] = useState("150");

  const { data: gameSettings, isLoading } = useQuery<AllGameSettings>({
    queryKey: ["/api/admin/game-settings"],
  });

  const [slotsSettings, setSlotsSettings] = useState({
    winChance: 10,
    maxMultiplier: 1.1,
  });

  const [diceSettings, setDiceSettings] = useState({
    winChance: 10,
    maxMultiplier: 1.1,
  });

  const [plinkoSettings, setPlinkoSettings] = useState({
    winChance: 10,
    maxMultiplier: 1.1,
  });

  // Update local state when we get data from the server
  useState(() => {
    if (gameSettings) {
      setSlotsSettings({
        winChance: gameSettings.slots.winChance,
        maxMultiplier: gameSettings.slots.maxMultiplier,
      });
      setDiceSettings({
        winChance: gameSettings.dice.winChance,
        maxMultiplier: gameSettings.dice.maxMultiplier,
      });
      setPlinkoSettings({
        winChance: gameSettings.plinko.winChance,
        maxMultiplier: gameSettings.plinko.maxMultiplier,
      });
    }
  });

  const updateGameSettingsMutation = useMutation({
    mutationFn: async ({
      gameType,
      winChance,
      maxMultiplier,
    }: {
      gameType: GameType;
      winChance: number;
      maxMultiplier: number;
    }) => {
      const res = await apiRequest("POST", `/api/admin/game-settings/${gameType}`, {
        winChance,
        maxMultiplier,
      });
      return res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/admin/game-settings"] });
      toast({
        title: "Success",
        description: "Game settings updated successfully",
      });
    },
    onError: (error: Error) => {
      toast({
        title: "Error",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const handleSaveSettings = (gameType: GameType) => {
    let settings;

    switch (gameType) {
      case GameType.SLOTS:
        settings = slotsSettings;
        break;
      case GameType.DICE:
        settings = diceSettings;
        break;
      case GameType.PLINKO:
        settings = plinkoSettings;
        break;
      default:
        return;
    }

    updateGameSettingsMutation.mutate({
      gameType,
      winChance: settings.winChance,
      maxMultiplier: settings.maxMultiplier,
    });
  };

  if (isLoading) {
    return (
      <div className="bg-background-darker rounded-xl p-6 flex justify-center items-center h-64">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="bg-background-darker rounded-xl p-4 mb-6">
      <h3 className="font-medium text-white mb-4">Game Control Settings</h3>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {/* Slots Settings */}
        <div className="bg-background-light p-4 rounded-lg">
          <h4 className="font-medium text-white mb-2">Slots Settings</h4>
          <div className="space-y-3">
            <div>
              <div className="flex justify-between">
                <Label className="block text-gray-400 text-sm mb-1">Win Chance (%)</Label>
                <span className="text-white text-sm">{slotsSettings.winChance}%</span>
              </div>
              <Slider
                value={[slotsSettings.winChance]}
                min={0}
                max={100}
                step={1}
                onValueChange={(value) => setSlotsSettings({ ...slotsSettings, winChance: value[0] })}
                className="my-2"
              />
              <div className="flex justify-between text-xs text-gray-400">
                <span>0%</span>
                <span>50%</span>
                <span>100%</span>
              </div>
            </div>
            <div>
              <div className="flex justify-between">
                <Label className="block text-gray-400 text-sm mb-1">Max Multiplier</Label>
                <span className="text-white text-sm">{slotsSettings.maxMultiplier}x</span>
              </div>
              <Input
                type="number"
                value={slotsSettings.maxMultiplier}
                onChange={(e) => setSlotsSettings({
                  ...slotsSettings,
                  maxMultiplier: parseFloat(e.target.value) || 1.1,
                })}
                step="0.1"
                min="1.0"
                max="150"
                className="w-full bg-background-darker border-gray-800 rounded-lg px-4 py-2 text-white text-sm focus:outline-none focus:ring-2 focus:ring-primary"
              />
            </div>
            <Button 
              className="w-full mt-2" 
              onClick={() => handleSaveSettings(GameType.SLOTS)}
              disabled={updateGameSettingsMutation.isPending}
            >
              {updateGameSettingsMutation.isPending ? (
                <Loader2 className="h-4 w-4 animate-spin mr-2" />
              ) : null}
              Save Slots Settings
            </Button>
          </div>
        </div>

        {/* Dice Settings */}
        <div className="bg-background-light p-4 rounded-lg">
          <h4 className="font-medium text-white mb-2">Dice Settings</h4>
          <div className="space-y-3">
            <div>
              <div className="flex justify-between">
                <Label className="block text-gray-400 text-sm mb-1">Win Chance (%)</Label>
                <span className="text-white text-sm">{diceSettings.winChance}%</span>
              </div>
              <Slider
                value={[diceSettings.winChance]}
                min={0}
                max={100}
                step={1}
                onValueChange={(value) => setDiceSettings({ ...diceSettings, winChance: value[0] })}
                className="my-2"
              />
              <div className="flex justify-between text-xs text-gray-400">
                <span>0%</span>
                <span>50%</span>
                <span>100%</span>
              </div>
            </div>
            <div>
              <div className="flex justify-between">
                <Label className="block text-gray-400 text-sm mb-1">Max Multiplier</Label>
                <span className="text-white text-sm">{diceSettings.maxMultiplier}x</span>
              </div>
              <Input
                type="number"
                value={diceSettings.maxMultiplier}
                onChange={(e) => setDiceSettings({
                  ...diceSettings,
                  maxMultiplier: parseFloat(e.target.value) || 1.1,
                })}
                step="0.1"
                min="1.0"
                max="150"
                className="w-full bg-background-darker border-gray-800 rounded-lg px-4 py-2 text-white text-sm focus:outline-none focus:ring-2 focus:ring-primary"
              />
            </div>
            <Button 
              className="w-full mt-2" 
              onClick={() => handleSaveSettings(GameType.DICE)}
              disabled={updateGameSettingsMutation.isPending}
            >
              {updateGameSettingsMutation.isPending ? (
                <Loader2 className="h-4 w-4 animate-spin mr-2" />
              ) : null}
              Save Dice Settings
            </Button>
          </div>
        </div>

        {/* Plinko Settings */}
        <div className="bg-background-light p-4 rounded-lg">
          <h4 className="font-medium text-white mb-2">Plinko Settings</h4>
          <div className="space-y-3">
            <div>
              <div className="flex justify-between">
                <Label className="block text-gray-400 text-sm mb-1">Win Chance (%)</Label>
                <span className="text-white text-sm">{plinkoSettings.winChance}%</span>
              </div>
              <Slider
                value={[plinkoSettings.winChance]}
                min={0}
                max={100}
                step={1}
                onValueChange={(value) => setPlinkoSettings({ ...plinkoSettings, winChance: value[0] })}
                className="my-2"
              />
              <div className="flex justify-between text-xs text-gray-400">
                <span>0%</span>
                <span>50%</span>
                <span>100%</span>
              </div>
            </div>
            <div>
              <div className="flex justify-between">
                <Label className="block text-gray-400 text-sm mb-1">Max Multiplier</Label>
                <span className="text-white text-sm">{plinkoSettings.maxMultiplier}x</span>
              </div>
              <Input
                type="number"
                value={plinkoSettings.maxMultiplier}
                onChange={(e) => setPlinkoSettings({
                  ...plinkoSettings,
                  maxMultiplier: parseFloat(e.target.value) || 1.1,
                })}
                step="0.1"
                min="1.0"
                max="150"
                className="w-full bg-background-darker border-gray-800 rounded-lg px-4 py-2 text-white text-sm focus:outline-none focus:ring-2 focus:ring-primary"
              />
            </div>
            <Button 
              className="w-full mt-2" 
              onClick={() => handleSaveSettings(GameType.PLINKO)}
              disabled={updateGameSettingsMutation.isPending}
            >
              {updateGameSettingsMutation.isPending ? (
                <Loader2 className="h-4 w-4 animate-spin mr-2" />
              ) : null}
              Save Plinko Settings
            </Button>
          </div>
        </div>

        {/* Global Settings */}
        <div className="bg-background-light p-4 rounded-lg">
          <h4 className="font-medium text-white mb-2">Global Settings</h4>
          <div className="space-y-3">
            <div>
              <Label className="block text-gray-400 text-sm mb-1">Maximum Win Limit (BDT)</Label>
              <Input
                type="number"
                value={maxWinLimit}
                onChange={(e) => setMaxWinLimit(e.target.value)}
                className="w-full bg-background-darker border-gray-800 rounded-lg px-4 py-2 text-white text-sm focus:outline-none focus:ring-2 focus:ring-primary"
              />
              <p className="text-gray-400 text-xs mt-1">This is enforced at the API level, no changes needed here.</p>
            </div>
            <div className="flex items-center space-x-2 pt-2">
              <Switch
                id="rigged"
                checked={riggedMode}
                onCheckedChange={setRiggedMode}
              />
              <Label htmlFor="rigged" className="text-white text-sm">Enable rigged mode</Label>
            </div>
            <p className="text-gray-400 text-xs mt-1">Rigged mode is always enforced in the backend code.</p>
          </div>
        </div>
      </div>
    </div>
  );
}

client/src/components/admin/GameSettings.content:
import { useState, useEffect } from "react";
import { 
  Tabs, TabsContent, TabsList, TabsTrigger 
} from "@/components/ui/tabs";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { 
  AlertCircle, Save, RefreshCw, 
  Lock, Gamepad2, Dice5, Box
} from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { Slider } from "@/components/ui/slider";
import { GameType } from "@shared/schema";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { Progress } from "@/components/ui/progress";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";
import { adminApiCall } from "@/lib/api";

type GameSetting = {
  id: number;
  gameType: GameType;
  winChance: number;
  maxMultiplier: number;
  updatedBy: number;
  updatedAt: string;
};

export function GameSettings() {
  const { toast } = useToast();
  const [gameSettings, setGameSettings] = useState<{
    slots?: GameSetting;
    dice?: GameSetting;
    plinko?: GameSetting;
  }>({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isSaving, setIsSaving] = useState(false);
  const [editedSettings, setEditedSettings] = useState<{
    [GameType.SLOTS]: { winChance: number; maxMultiplier: number };
    [GameType.DICE]: { winChance: number; maxMultiplier: number };
    [GameType.PLINKO]: { winChance: number; maxMultiplier: number };
  }>({
    [GameType.SLOTS]: { winChance: 45, maxMultiplier: 1.1 },
    [GameType.DICE]: { winChance: 45, maxMultiplier: 1.1 },
    [GameType.PLINKO]: { winChance: 45, maxMultiplier: 1.1 }
  });
  const [winLock, setWinLock] = useState({
    enabled: true,
    threshold: 150 // BDT
  });

  useEffect(() => {
    async function fetchGameSettings() {
      try {
        setLoading(true);
        const data = await adminApiCall<{
          slots?: GameSetting;
          dice?: GameSetting;
          plinko?: GameSetting;
        }>('GET', "/api/admin/game-settings");

        setGameSettings(data);

        // Initialize edited settings with current values
        setEditedSettings({
          [GameType.SLOTS]: { 
            winChance: data.slots?.winChance || 45, 
            maxMultiplier: data.slots?.maxMultiplier || 1.1 
          },
          [GameType.DICE]: { 
            winChance: data.dice?.winChance || 45, 
            maxMultiplier: data.dice?.maxMultiplier || 1.1 
          },
          [GameType.PLINKO]: { 
            winChance: data.plinko?.winChance || 45, 
            maxMultiplier: data.plinko?.maxMultiplier || 1.1 
          }
        });
      } catch (err) {
        console.error("Error fetching game settings:", err);
        setError(err instanceof Error ? err.message : "Failed to load game settings");

        toast({
          title: "Error Loading Game Settings",
          description: err instanceof Error ? err.message : "An error occurred while loading game settings",
          variant: "destructive",
        });
      } finally {
        setLoading(false);
      }
    }

    fetchGameSettings();
  }, [toast]);

  const saveGameSettings = async (gameType: GameType) => {
    try {
      setIsSaving(true);
      const settings = editedSettings[gameType];

      const updatedSettings = await adminApiCall<GameSetting>(
        'POST', 
        `/api/admin/game-settings/${gameType}`,
        {
          winChance: settings.winChance.toString(),
          maxMultiplier: settings.maxMultiplier.toString()
        }
      );

      // Update local state
      setGameSettings({
        ...gameSettings,
        [gameType]: updatedSettings
      });

      toast({
        title: "Settings Updated",
        description: `${gameType.charAt(0).toUpperCase() + gameType.slice(1)} game settings have been updated successfully`,
      });
    } catch (err) {
      console.error(`Error updating ${gameType} settings:`, err);

      toast({
        title: "Update Failed",
        description: err instanceof Error ? err.message : `An error occurred while updating ${gameType} settings`,
        variant: "destructive",
      });
    } finally {
      setIsSaving(false);
    }
  };

  // Calculate house edge
  const calculateHouseEdge = (winChance: number, maxMultiplier: number) => {
    // House edge formula: 1 - (winChance / 100 * maxMultiplier)
    return ((1 - (winChance / 100 * maxMultiplier)) * 100).toFixed(2);
  };

  const getProfitColor = (houseEdge: number) => {
    if (houseEdge > 30) return "text-green-500";
    if (houseEdge > 20) return "text-lime-500";
    if (houseEdge > 10) return "text-amber-500";
    return "text-red-500";
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin h-8 w-8 border-4 border-primary border-t-transparent rounded-full"></div>
        <span className="ml-3">Loading game settings...</span>
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-500/10 border border-red-500/30 rounded-md p-4 flex items-start">
        <AlertCircle className="text-red-500 mr-3 mt-0.5 flex-shrink-0" />
        <div>
          <h3 className="text-red-500 font-medium mb-1">Error Loading Game Settings</h3>
          <p className="text-red-400 text-sm">{error}</p>
          <button 
            className="mt-2 px-3 py-1 bg-red-500/20 hover:bg-red-500/30 text-red-500 rounded text-sm"
            onClick={() => window.location.reload()}
          >
            Try Again
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Win Lock Settings */}
      <Card className="border-amber-500/20">
        <CardHeader className="pb-2">
          <div className="flex items-center">
            <Lock className="h-5 w-5 text-amber-500 mr-2" />
            <CardTitle>Win Lock Mechanism</CardTitle>
          </div>
          <CardDescription>
            When enabled, players with balances above the threshold will have 0% chance of winning
          </CardDescription>
        </CardHeader>
        <CardContent>
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center space-x-2">
              <Switch 
                id="win-lock" 
                checked={winLock.enabled}
                onCheckedChange={(checked) => setWinLock({...winLock, enabled: checked})}
              />
              <Label htmlFor="win-lock">
                {winLock.enabled ? "Enabled" : "Disabled"}
              </Label>
            </div>
            <div className="text-sm text-amber-500">
              {winLock.enabled 
                ? "Players cannot win once they reach the threshold" 
                : "All players have standard win chances"}
            </div>
          </div>

          <div className="space-y-2">
            <div className="flex justify-between">
              <Label htmlFor="win-lock-threshold">Win Lock Threshold (BDT)</Label>
              <span>{winLock.threshold} BDT</span>
            </div>
            <Slider
              id="win-lock-threshold"
              disabled={!winLock.enabled}
              value={[winLock.threshold]}
              max={1000}
              min={50}
              step={10}
              onValueChange={(value) => setWinLock({...winLock, threshold: value[0]})}
              className={!winLock.enabled ? "opacity-50" : ""}
            />
            <div className="flex justify-between text-xs text-gray-400">
              <span>50 BDT</span>
              <span>1000 BDT</span>
            </div>
          </div>
        </CardContent>
        <CardFooter>
          <Button 
            disabled={!winLock.enabled}
            className="w-full"
            onClick={() => {
              toast({
                title: "Win Lock Updated",
                description: `Win lock threshold has been set to ${winLock.threshold} BDT`,
              });
            }}
          >
            <Save className="h-4 w-4 mr-2" />
            Save Win Lock Settings
          </Button>
        </CardFooter>
      </Card>

      {/* Game-specific settings */}
      <Tabs defaultValue={GameType.SLOTS}>
        <TabsList className="grid w-full grid-cols-3">
          <TabsTrigger value={GameType.SLOTS} className="flex items-center justify-center">
            <Gamepad2 className="h-4 w-4 mr-2" />
            <span>Slots</span>
          </TabsTrigger>
          <TabsTrigger value={GameType.DICE} className="flex items-center justify-center">
            <Dice5 className="h-4 w-4 mr-2" />
            <span>Dice</span>
          </TabsTrigger>
          <TabsTrigger value={GameType.PLINKO} className="flex items-center justify-center">
            <Box className="h-4 w-4 mr-2" />
            <span>Plinko</span>
          </TabsTrigger>
        </TabsList>

        {/* Slots Settings */}
        <TabsContent value={GameType.SLOTS}>
          <Card>
            <CardHeader>
              <CardTitle>Slots Game Settings</CardTitle>
              <CardDescription>
                Configure win chances and multipliers for Slots game
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-6">
              {/* Win Chance */}
              <div className="space-y-2">
                <div className="flex justify-between">
                  <Label>Win Chance (%)</Label>
                  <div className="flex items-center space-x-2">
                    <Input
                      type="number"
                      value={editedSettings[GameType.SLOTS].winChance}
                      onChange={(e) => setEditedSettings({
                        ...editedSettings,
                        [GameType.SLOTS]: {
                          ...editedSettings[GameType.SLOTS],
                          winChance: parseFloat(e.target.value) || 0
                        }
                      })}
                      min="0"
                      max="100"
                      step="1"
                      className="w-20 text-right"
                    />
                    <span>%</span>
                  </div>
                </div>
                <Slider
                  value={[editedSettings[GameType.SLOTS].winChance]}
                  max={100}
                  min={0}
                  step={1}
                  onValueChange={(value) => setEditedSettings({
                    ...editedSettings,
                    [GameType.SLOTS]: {
                      ...editedSettings[GameType.SLOTS],
                      winChance: value[0]
                    }
                  })}
                />
                <Progress value={editedSettings[GameType.SLOTS].winChance} className="h-2" />
              </div>

              {/* Max Multiplier */}
              <div className="space-y-2">
                <div className="flex justify-between">
                  <Label>Max Win Multiplier</Label>
                  <div className="flex items-center space-x-2">
                    <Input
                      type="number"
                      value={editedSettings[GameType.SLOTS].maxMultiplier}
                      onChange={(e) => setEditedSettings({
                        ...editedSettings,
                        [GameType.SLOTS]: {
                          ...editedSettings[GameType.SLOTS],
                          maxMultiplier: parseFloat(e.target.value) || 0
                        }
                      })}
                      min="1"
                      max="10"
                      step="0.1"
                      className="w-20 text-right"
                    />
                    <span>x</span>
                  </div>
                </div>
                <Slider
                  value={[editedSettings[GameType.SLOTS].maxMultiplier * 10]}
                  max={50}
                  min={10}
                  step={1}
                  onValueChange={(value) => setEditedSettings({
                    ...editedSettings,
                    [GameType.SLOTS]: {
                      ...editedSettings[GameType.SLOTS],
                      maxMultiplier: value[0] / 10
                    }
                  })}
                />
                <div className="flex justify-between text-xs text-gray-400">
                  <span>1.0x</span>
                  <span>5.0x</span>
                </div>
              </div>

              {/* House Edge Calculation */}
              <Card className="border-green-500/20">
                <CardContent className="pt-6">
                  <div className="flex justify-between items-center">
                    <div>
                      <h3 className="font-medium">House Edge</h3>
                      <p className="text-sm text-gray-400">
                        Expected profit margin based on current settings
                      </p>
                    </div>
                    <div className={`text-3xl font-bold ${getProfitColor(
                      parseFloat(calculateHouseEdge(
                        editedSettings[GameType.SLOTS].winChance, 
                        editedSettings[GameType.SLOTS].maxMultiplier
                      ))
                    )}`}>
                      {calculateHouseEdge(
                        editedSettings[GameType.SLOTS].winChance, 
                        editedSettings[GameType.SLOTS].maxMultiplier
                      )}%
                    </div>
                  </div>
                </CardContent>
              </Card>
            </CardContent>
            <CardFooter className="flex justify-between">
              <Button 
                variant="outline" 
                onClick={() => setEditedSettings({
                  ...editedSettings,
                  [GameType.SLOTS]: { winChance: 45, maxMultiplier: 1.1 }
                })}
              >
                <RefreshCw className="h-4 w-4 mr-2" />
                Reset to Default
              </Button>
              <Button 
                onClick={() => saveGameSettings(GameType.SLOTS)}
                disabled={isSaving}
              >
                {isSaving ? (
                  <>
                    <div className="animate-spin h-4 w-4 border-2 border-white border-t-transparent rounded-full mr-2"></div>
                    Saving...
                  </>
                ) : (
                  <>
                    <Save className="h-4 w-4 mr-2" />
                    Save Settings
                  </>
                )}
              </Button>
            </CardFooter>
          </Card>
        </TabsContent>

        {/* Dice Settings */}
        <TabsContent value={GameType.DICE}>
