            username: "shadowHimel",
            email: "shadowhimel@example.com",
            balance: "10000",
            currency: "USD",
            role: "admin",
            isMuted: false,
            isBanned: false,
            createdAt: new Date().toISOString()
          },
          {
            id: 3,
            username: "Albab AJ",
