          description: err instanceof Error ? err.message : t('admin.errorUpdatingUser'),
          variant: "destructive",
        });
      } finally {
        setLoading(false);
      }
    }

    fetchUsers();
  }, [toast]);

  const toggleUserBan = async (userId: number, isBanned: boolean) => {
    try {
      await adminApiCall('POST', `/api/admin/user/${userId}/ban`, { isBanned });

      // Update local state
      setUsers(users.map(user => 
        user.id === userId ? { ...user, isBanned } : user
      ));

      toast({
        title: isBanned ? t('admin.userBanned') : t('admin.userUnbanned'),
