import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { 
  Shield, X, CheckCircle, Download, 
  RotateCcw, Settings
} from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { themeManager } from "@/lib/theme-manager";
import { ThemeRecovery } from "./ThemeRecovery";

export function ThemeProtectionNotice() {
  const [isVisible, setIsVisible] = useState(false);
  const [hasBackup, setHasBackup] = useState(false);
  const { toast } = useToast();

  useEffect(() => {
    // Check if user has seen this notice before
    const hasSeenNotice = localStorage.getItem("theme-protection-notice-seen");
    const backupInfo = themeManager.getBackupInfo();

    setHasBackup(!!backupInfo);

    // Show notice if user hasn't seen it or if there's no backup
    if (!hasSeenNotice || !backupInfo) {
      setIsVisible(true);
    }
  }, []);

  const handleDismiss = () => {
    setIsVisible(false);
    localStorage.setItem("theme-protection-notice-seen", "true");
  };

  const handleCreateBackup = () => {
    try {
      // Get current theme preferences
      const preferences = themeManager.getThemePreferences();
      const allThemes = themeManager.mergeThemes([]);

      // Create backup
      themeManager.createBackup(allThemes, preferences.activeThemeId);

      setHasBackup(true);
      toast({
        title: "Backup Created Successfully",
        description: "Your themes are now protected from loss",
      });
    } catch (error) {
      toast({
        title: "Backup Failed",
        description: "Unable to create theme backup",
        variant: "destructive",
      });
    }
  };

  if (!isVisible) return null;

  return (
    <div className="fixed top-4 right-4 z-50 w-96 animate-slide-in">
      <Card className="luxury-card border-yellow-500/50 shadow-2xl">
        <CardHeader className="pb-3">
          <div className="flex items-center justify-between">
            <CardTitle className="text-lg text-yellow-500 glow-text flex items-center">
              <Shield className="h-5 w-5 mr-2" />
              Theme Protection Active
            </CardTitle>
            <Button
              variant="ghost"
              size="sm"
              onClick={handleDismiss}
              className="h-8 w-8 p-0"
            >
              <X className="h-4 w-4" />
            </Button>
          </div>
        </CardHeader>

        <CardContent className="space-y-4">
          <Alert className="border-green-500/50 bg-green-500/10">
            <CheckCircle className="h-4 w-4" />
            <AlertDescription>
              Enhanced theme management system is now active. Your theme preferences 
              will be automatically preserved and protected from unexpected changes.
            </AlertDescription>
          </Alert>

          <div className="space-y-3">
            <div className="text-sm text-gray-300 space-y-2">
              <div className="flex items-center gap-2">
                <CheckCircle className="h-3 w-3 text-green-400" />
                <span>Automatic theme backup on changes</span>
              </div>
              <div className="flex items-center gap-2">
                <CheckCircle className="h-3 w-3 text-green-400" />
                <span>Custom theme preservation</span>
              </div>
              <div className="flex items-center gap-2">
                <CheckCircle className="h-3 w-3 text-green-400" />
                <span>Favorites and recent themes saved</span>
              </div>
              <div className="flex items-center gap-2">
                <CheckCircle className="h-3 w-3 text-green-400" />
                <span>One-click theme recovery</span>
              </div>
            </div>

            {!hasBackup && (
              <div className="pt-2">
                <Button 
                  onClick={handleCreateBackup}
                  className="w-full luxury-button"
                  size="sm"
                >
                  <Shield className="h-4 w-4 mr-2" />
                  Create Initial Backup
                </Button>
              </div>
            )}

            <div className="flex gap-2 pt-2">
              <ThemeRecovery />
              <Button
                variant="outline"
                size="sm"
                onClick={handleDismiss}
                className="flex-1"
              >
                <Settings className="h-4 w-4 mr-2" />
                Got It
              </Button>
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

client/src/components/common/ThemeRecove.content:
import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { 
  Shield, RotateCcw, Download, Upload, Save, 
  AlertTriangle, CheckCircle, History
} from "lucide-react";
import { useToast } from "@/hooks/use-toast";
import { themeManager } from "@/lib/theme-manager";
import { useTheme } from "@/hooks/use-theme";

export function ThemeRecovery() {
  const [isOpen, setIsOpen] = useState(false);
  const [backupInfo, setBackupInfo] = useState<{ timestamp: number, version: string } | null>(null);
  const [isRestoring, setIsRestoring] = useState(false);
  const { toast } = useToast();
  const { currentTheme, setTheme, availableThemes } = useTheme();

  useEffect(() => {
    const info = themeManager.getBackupInfo();
    setBackupInfo(info);
  }, []);

  const handleQuickRestore = async () => {
    setIsRestoring(true);
    try {
      const backup = themeManager.restoreFromBackup();
      if (backup) {
        if (backup.activeThemeId) {
          setTheme(backup.activeThemeId);
        }
        toast({
          title: "Themes Restored",
          description: "Your previous theme settings have been recovered",
        });
      } else {
        toast({
          title: "No Backup Available",
          description: "No previous backup found to restore from",
          variant: "destructive",
        });
      }
    } catch (error) {
      toast({
        title: "Restore Failed",
        description: "Unable to restore themes from backup",
        variant: "destructive",
      });
    } finally {
      setIsRestoring(false);
    }
  };

  const handleCreateProtectedBackup = () => {
    themeManager.createBackup(availableThemes, currentTheme.id);
    const info = themeManager.getBackupInfo();
    setBackupInfo(info);

    toast({
      title: "Protected Backup Created",
      description: "Your current theme settings are now safely backed up",
    });
  };

  const handleExportSecure = () => {
    const exportData = themeManager.exportThemes(availableThemes, currentTheme.id);
    const blob = new Blob([exportData], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `shadow-casino-secure-backup-${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);

    toast({
      title: "Secure Export Complete",
      description: "Your complete theme collection has been exported safely",
    });
  };

  const handleImportSecure = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        const content = e.target?.result as string;
        const result = themeManager.importThemes(content);

        if (result.success) {
          if (result.activeThemeId) {
            setTheme(result.activeThemeId);
          }
          toast({
            title: "Import Successful",
            description: result.message,
          });
          setIsOpen(false);
        } else {
          toast({
            title: "Import Failed",
            description: result.message,
            variant: "destructive",
          });
        }
      };
      reader.readAsText(file);
    }
  };

  const formatDate = (timestamp: number) => {
    return new Date(timestamp).toLocaleString();
  };

  return (
    <Dialog open={isOpen} onOpenChange={setIsOpen}>
      <DialogTrigger asChild>
        <Button variant="outline" size="sm" className="luxury-button">
          <Shield className="h-4 w-4 mr-2" />
          Theme Recovery
        </Button>
      </DialogTrigger>

      <DialogContent className="luxury-card max-w-2xl">
        <DialogHeader>
          <DialogTitle className="text-2xl font-bold text-yellow-500 glow-text flex items-center">
            <Shield className="h-6 w-6 mr-2" />
            Theme Recovery Center
          </DialogTitle>
        </DialogHeader>

        <div className="space-y-6">
          {/* Backup Status */}
          <Card className="luxury-card">
            <CardHeader>
              <CardTitle className="text-lg text-white flex items-center">
                <History className="h-5 w-5 mr-2" />
                Backup Status
              </CardTitle>
            </CardHeader>
            <CardContent>
              {backupInfo ? (
                <div className="space-y-3">
                  <Alert className="border-green-500/50 bg-green-500/10">
                    <CheckCircle className="h-4 w-4" />
                    <AlertDescription>
                      Backup available from {formatDate(backupInfo.timestamp)}
                      <Badge variant="outline" className="ml-2">v{backupInfo.version}</Badge>
                    </AlertDescription>
                  </Alert>

                  <Button 
                    onClick={handleQuickRestore}
                    disabled={isRestoring}
                    className="w-full luxury-button"
                  >
                    <RotateCcw className={`h-4 w-4 mr-2 ${isRestoring ? 'animate-spin' : ''}`} />
                    {isRestoring ? 'Restoring...' : 'Quick Restore Themes'}
                  </Button>
                </div>
              ) : (
                <div className="space-y-3">
                  <Alert className="border-yellow-500/50 bg-yellow-500/10">
                    <AlertTriangle className="h-4 w-4" />
                    <AlertDescription>
                      No backup found. Create one now to protect your themes.
                    </AlertDescription>
                  </Alert>

                  <Button 
                    onClick={handleCreateProtectedBackup}
                    className="w-full luxury-button"
                  >
                    <Save className="h-4 w-4 mr-2" />
                    Create Protected Backup
                  </Button>
                </div>
              )}
            </CardContent>
          </Card>

          {/* Advanced Recovery Options */}
          <Card className="luxury-card">
            <CardHeader>
              <CardTitle className="text-lg text-white">Advanced Recovery</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                <Button 
                  onClick={handleExportSecure}
                  variant="outline" 
                  className="w-full"
                >
                  <Download className="h-4 w-4 mr-2" />
                  Export Secure Backup
                </Button>

                <div>
                  <input
                    type="file"
                    accept=".json"
                    onChange={handleImportSecure}
                    className="hidden"
                    id="secure-import"
