  useEffect(() => {
    const fetchCustomGames = async () => {
      if (!user) return;

      try {
        setLoadingGames(true);
        const response = await fetch('/api/games/custom');
        if (response.ok) {
          const games = await response.json();
          setCustomGames(games.filter((game: CustomGame) => game.isActive));
