  });

export const recordWin = (gameType: 'SLOTS' | 'DICE' | 'PLINKO', amount: number, currency: string, multiplier?: number, gameData?: any) =>
  realTimeBalance.processGameTransaction({
    gameType,
    amount,
    currency,
