class RouletteGame {
    constructor() {
        this.canvas = null;
        this.ctx = null;
        this.wheel = null;
        this.ball = null;
        this.isSpinning = false;
        this.betAmount = 1.00;
        this.selectedBets = [];

        this.numbers = [
            0, 32, 15, 19, 4, 21, 2, 25, 17, 34, 6, 27, 13, 36, 11, 30, 8, 23, 10, 5,
            24, 16, 33, 1, 20, 14, 31, 9, 22, 18, 29, 7, 28, 12, 35, 3, 26
        ];

        this.redNumbers = [1, 3, 5, 7, 9, 12, 14, 16, 18, 19, 21, 23, 25, 27, 30, 32, 34, 36];

        this.init();
    }

    init() {
        this.createGameHTML();
        this.initCanvas();
        this.drawWheel();
        this.setupEventListeners();
    }

    createGameHTML() {
        document.body.innerHTML = `
            <div class="casino-game-container">
                <h1>🎯 Roulette Wheel</h1>
                <p>Your Balance: <span class="casino-balance">Loading...</span></p>

                <div class="game-area">
                    <canvas id="rouletteCanvas" width="400" height="400"></canvas>

                    <div class="betting-area">
                        <h3>Place Your Bets</h3>

                        <div class="bet-controls">
                            <label>Bet Amount:</label>
                            <input type="number" id="betAmount" value="1.00" min="0.01" step="0.01">
                        </div>

                        <div class="bet-types">
                            <div class="bet-section">
                                <h4>Number Bets (35:1)</h4>
                                <div class="number-grid">
